    private function table_exists_cached( $table_name ) {
        global $wpdb;

        $table_name = (string) $table_name;
        if ( isset( self::$n88_table_exists_cache[ $table_name ] ) ) {
            return self::$n88_table_exists_cache[ $table_name ];
        }

        self::$n88_table_exists_cache[ $table_name ] = ( $wpdb->get_var( "SHOW TABLES LIKE '{$table_name}'" ) === $table_name );
        return self::$n88_table_exists_cache[ $table_name ];
    }

    private function table_columns_cached( $table_name ) {
        global $wpdb;

        $table_name = (string) $table_name;
        if ( isset( self::$n88_table_columns_cache[ $table_name ] ) ) {
            return self::$n88_table_columns_cache[ $table_name ];
        }

        if ( ! $this->table_exists_cached( $table_name ) ) {
            self::$n88_table_columns_cache[ $table_name ] = array();
            return self::$n88_table_columns_cache[ $table_name ];
        }

        $columns = $wpdb->get_col( "DESCRIBE {$table_name}" );
        self::$n88_table_columns_cache[ $table_name ] = is_array( $columns ) ? $columns : array();
        return self::$n88_table_columns_cache[ $table_name ];
    }

    /**
     * Commit 3.C.13: Resolve the default Wireframe maker account used on every RFQ.
     *
     * @return int Supplier user ID, or 0 if the account is unavailable.
     */
    private function get_default_wireframe_supplier_id() {
        $wireframe_user = get_user_by( 'email', self::N88_DEFAULT_WIREFRAME_SUPPLIER_EMAIL );
        if ( ! $wireframe_user || ! in_array( 'n88_supplier_admin', (array) $wireframe_user->roles, true ) ) {
            return 0;
        }

        return (int) $wireframe_user->ID;
    }

    /**
     * Resolve the supplier context for a direct designer <-> supplier thread on an item.
     *
     * Priority:
     * 1. Awarded bid supplier
     * 2. Latest prototype payment supplier
     * 3. Single active routed supplier
     * 4. Single submitted/awarded bid supplier
     * 5. Latest existing designer_supplier thread supplier
     *
     * @param int $item_id Item ID.
     * @return int Supplier ID or 0 when ambiguous/unavailable.
     */
    private function resolve_designer_supplier_thread_supplier_id( $item_id ) {
        global $wpdb;

        $item_id = absint( $item_id );
        if ( ! $item_id ) {
            return 0;
        }

        $item_bids_table         = $wpdb->prefix . 'n88_item_bids';
        $prototype_payments_table = $wpdb->prefix . 'n88_prototype_payments';
        $rfq_routes_table        = $wpdb->prefix . 'n88_rfq_routes';
        $messages_table          = $wpdb->prefix . 'n88_item_messages';

        $awarded_supplier_id = (int) $wpdb->get_var( $wpdb->prepare(
            "SELECT supplier_id
            FROM {$item_bids_table}
            WHERE item_id = %d AND status = 'awarded'
            ORDER BY bid_id DESC
            LIMIT 1",
            $item_id
        ) );
        if ( $awarded_supplier_id > 0 ) {
            return $awarded_supplier_id;
        }

        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$prototype_payments_table}'" ) === $prototype_payments_table ) {
            $prototype_supplier_id = (int) $wpdb->get_var( $wpdb->prepare(
                "SELECT supplier_id
                FROM {$prototype_payments_table}
                WHERE item_id = %d AND supplier_id IS NOT NULL
                ORDER BY id DESC
                LIMIT 1",
                $item_id
            ) );
            if ( $prototype_supplier_id > 0 ) {
                return $prototype_supplier_id;
            }
        }

        $active_route_suppliers = $wpdb->get_col( $wpdb->prepare(
            "SELECT DISTINCT supplier_id
            FROM {$rfq_routes_table}
            WHERE item_id = %d
            AND (status IS NULL OR status != 'expired')
            AND supplier_id IS NOT NULL",
            $item_id
        ) );
        $active_route_suppliers = array_values( array_filter( array_map( 'absint', (array) $active_route_suppliers ) ) );
        if ( count( $active_route_suppliers ) === 1 ) {
            return (int) $active_route_suppliers[0];
        }

        $bid_suppliers = $wpdb->get_col( $wpdb->prepare(
            "SELECT DISTINCT supplier_id
            FROM {$item_bids_table}
            WHERE item_id = %d
            AND status IN ('submitted', 'awarded')
            AND supplier_id IS NOT NULL",
            $item_id
        ) );
        $bid_suppliers = array_values( array_filter( array_map( 'absint', (array) $bid_suppliers ) ) );
        if ( count( $bid_suppliers ) === 1 ) {
            return (int) $bid_suppliers[0];
        }

        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$messages_table}'" ) === $messages_table ) {
            $message_supplier_id = (int) $wpdb->get_var( $wpdb->prepare(
                "SELECT supplier_id
                FROM {$messages_table}
                WHERE item_id = %d
                AND thread_type = 'designer_supplier'
                AND supplier_id IS NOT NULL
                ORDER BY message_id DESC
                LIMIT 1",
                $item_id
            ) );
            if ( $message_supplier_id > 0 ) {
                return $message_supplier_id;
            }
        }

        return 0;
    }

    /**
     * Resolve supplier IDs that should be available for direct designer <-> supplier messaging.
     *
     * Sources:
     * 1. RFQ routes (any non-expired route state)
     * 2. Item bids
     * 3. Prototype payments
     * 4. Existing designer_supplier messages
     *
     * @param int $item_id Item ID.
     * @return array<int>
     */
    private function get_designer_supplier_thread_supplier_ids( $item_id ) {
        global $wpdb;

        $item_id = absint( $item_id );
        if ( ! $item_id ) {
            return array();
        }

        $rfq_routes_table         = $wpdb->prefix . 'n88_rfq_routes';
        $item_bids_table          = $wpdb->prefix . 'n88_item_bids';
        $prototype_payments_table = $wpdb->prefix . 'n88_prototype_payments';
        $messages_table           = $wpdb->prefix . 'n88_item_messages';

        $supplier_ids = array();

        $route_supplier_ids = $wpdb->get_col( $wpdb->prepare(
            "SELECT DISTINCT supplier_id
            FROM {$rfq_routes_table}
            WHERE item_id = %d
            AND supplier_id IS NOT NULL
            AND (status IS NULL OR status != 'expired')",
            $item_id
        ) );
        $supplier_ids = array_merge( $supplier_ids, (array) $route_supplier_ids );

        $bid_supplier_ids = $wpdb->get_col( $wpdb->prepare(
            "SELECT DISTINCT supplier_id
            FROM {$item_bids_table}
            WHERE item_id = %d
            AND supplier_id IS NOT NULL",
            $item_id
        ) );
        $supplier_ids = array_merge( $supplier_ids, (array) $bid_supplier_ids );

        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$prototype_payments_table}'" ) === $prototype_payments_table ) {
            $prototype_supplier_ids = $wpdb->get_col( $wpdb->prepare(
                "SELECT DISTINCT supplier_id
                FROM {$prototype_payments_table}
                WHERE item_id = %d
                AND supplier_id IS NOT NULL",
                $item_id
            ) );
            $supplier_ids = array_merge( $supplier_ids, (array) $prototype_supplier_ids );
        }

        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$messages_table}'" ) === $messages_table ) {
            $message_supplier_ids = $wpdb->get_col( $wpdb->prepare(
                "SELECT DISTINCT supplier_id
                FROM {$messages_table}
                WHERE item_id = %d
                AND thread_type = 'designer_supplier'
                AND supplier_id IS NOT NULL",
                $item_id
            ) );
            $supplier_ids = array_merge( $supplier_ids, (array) $message_supplier_ids );
        }

        return array_values( array_unique( array_filter( array_map( 'absint', $supplier_ids ) ) ) );
    }

    /**
     * Check whether supplier has direct designer-thread access for an item.
     *
     * This is intentionally broader than active RFQ routing so post-RFQ commercial
     * messaging still works after bid/payment/award workflow transitions.
     *
     * @param int $item_id Item ID.
     * @param int $supplier_id Supplier user ID.
     * @return bool
     */
    private function supplier_has_designer_supplier_thread_access( $item_id, $supplier_id ) {
        $supplier_id = absint( $supplier_id );
        if ( ! $supplier_id ) {
            return false;
        }

        $supplier_ids = $this->get_designer_supplier_thread_supplier_ids( $item_id );
        return in_array( $supplier_id, $supplier_ids, true );
    }

    /**
     * Commit 3.C.14: Ensure additive tables/columns needed by the unified supplier proposal workspace.
     */
    private function ensure_supplier_proposal_workspace_support() {
        global $wpdb;

        static $workspace_support_ready = false;
        if ( $workspace_support_ready ) {
            return;
        }

        $charset_collate     = $wpdb->get_charset_collate();
        $groups_table        = $wpdb->prefix . 'n88_supplier_proposal_groups';
        $group_items_table   = $wpdb->prefix . 'n88_supplier_proposal_group_items';
        $group_uploads_table = $wpdb->prefix . 'n88_supplier_proposal_group_uploads';
        $messages_table      = $wpdb->prefix . 'n88_item_messages';

        $groups_table_exists        = $wpdb->get_var( "SHOW TABLES LIKE '{$groups_table}'" ) === $groups_table;
        $group_items_table_exists   = $wpdb->get_var( "SHOW TABLES LIKE '{$group_items_table}'" ) === $group_items_table;
        $group_uploads_table_exists = $wpdb->get_var( "SHOW TABLES LIKE '{$group_uploads_table}'" ) === $group_uploads_table;

        if ( ! $groups_table_exists || ! $group_items_table_exists || ! $group_uploads_table_exists ) {
            require_once ABSPATH . 'wp-admin/includes/upgrade.php';

            dbDelta(
                "CREATE TABLE {$groups_table} (
                    proposal_group_id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
                    supplier_id BIGINT UNSIGNED NOT NULL,
                    workspace_key VARCHAR(190) NOT NULL,
                    workspace_label VARCHAR(255) NULL,
                    rfq_reference VARCHAR(64) NULL,
                    designer_id BIGINT UNSIGNED NULL,
                    project_id BIGINT UNSIGNED NULL,
                    item_count INT UNSIGNED NOT NULL DEFAULT 0,
                    status VARCHAR(30) NOT NULL DEFAULT 'draft',
                    created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    PRIMARY KEY  (proposal_group_id),
                    UNIQUE KEY uq_supplier_workspace (supplier_id, workspace_key),
                    KEY idx_supplier_status (supplier_id, status),
                    KEY idx_designer_project (designer_id, project_id)
                ) {$charset_collate};"
            );

            dbDelta(
                "CREATE TABLE {$group_items_table} (
                    id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
                    proposal_group_id BIGINT UNSIGNED NOT NULL,
                    item_id BIGINT UNSIGNED NOT NULL,
                    supplier_id BIGINT UNSIGNED NOT NULL,
                    quote_decision VARCHAR(20) NOT NULL DEFAULT 'quote',
                    item_state VARCHAR(20) NOT NULL DEFAULT 'not_ready',
                    linked_bid_id BIGINT UNSIGNED NULL,
                    created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    PRIMARY KEY  (id),
                    UNIQUE KEY uq_group_item_supplier (proposal_group_id, item_id, supplier_id),
                    KEY idx_group_state (proposal_group_id, item_state),
                    KEY idx_supplier_item (supplier_id, item_id)
                ) {$charset_collate};"
            );

            dbDelta(
                "CREATE TABLE {$group_uploads_table} (
                    id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
                    proposal_group_id BIGINT UNSIGNED NOT NULL,
                    supplier_id BIGINT UNSIGNED NOT NULL,
                    attachment_id BIGINT UNSIGNED NULL,
                    file_url VARCHAR(500) NOT NULL,
                    file_name VARCHAR(255) NOT NULL,
                    created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    PRIMARY KEY  (id),
                    KEY idx_group_supplier (proposal_group_id, supplier_id),
                    KEY idx_attachment (attachment_id)
                ) {$charset_collate};"
            );
        }

        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$messages_table}'" ) === $messages_table ) {
            $thread_type_col = $wpdb->get_var( $wpdb->prepare(
                "SELECT COLUMN_TYPE FROM information_schema.COLUMNS WHERE TABLE_SCHEMA = %s AND TABLE_NAME = %s AND COLUMN_NAME = 'thread_type'",
                DB_NAME,
                $messages_table
            ) );

            if ( $thread_type_col && ( stripos( $thread_type_col, 'varchar' ) === false || strpos( $thread_type_col, 'designer_supplier' ) === false ) ) {
                $alter_result = $wpdb->query( "ALTER TABLE {$messages_table} MODIFY COLUMN thread_type VARCHAR(50) NOT NULL" );
                if ( false === $alter_result && ! empty( $wpdb->last_error ) ) {
                    error_log( 'N88 message thread_type migration failed: ' . $wpdb->last_error );
                }
            }
        }

        $workspace_support_ready = true;
    }

    /**
     * Commit 3.C.20: Ensure the unified item message table supports isolated contexts.
     *
     * @return void
     */
    private function ensure_item_message_context_support() {
        static $context_support_ready = false;

        if ( $context_support_ready ) {
            return;
        }

        global $wpdb;

        $messages_table = $wpdb->prefix . 'n88_item_messages';
        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$messages_table}'" ) !== $messages_table ) {
            $context_support_ready = true;
            return;
        }

        $context_col = $wpdb->get_var( $wpdb->prepare(
            "SELECT COLUMN_NAME FROM information_schema.COLUMNS WHERE TABLE_SCHEMA = %s AND TABLE_NAME = %s AND COLUMN_NAME = 'context_type'",
            DB_NAME,
            $messages_table
        ) );

        if ( ! $context_col ) {
            $alter_result = $wpdb->query( "ALTER TABLE {$messages_table} ADD COLUMN context_type VARCHAR(100) NULL AFTER category" );
            if ( false === $alter_result && ! empty( $wpdb->last_error ) ) {
                error_log( 'N88 message context_type migration failed: ' . $wpdb->last_error );
            }
        }

        $context_support_ready = true;
    }

    /**
     * Commit 3.C.33: Ensure supplier-level media library tables exist.
     */
    private function ensure_supplier_media_library_support() {
        static $media_library_support_ready = false;

        if ( $media_library_support_ready ) {
            return;
        }

        global $wpdb;
        require_once ABSPATH . 'wp-admin/includes/upgrade.php';

        $charset_collate        = $wpdb->get_charset_collate();
        $supplier_media_table   = $wpdb->prefix . 'n88_supplier_media';
        $supplier_materials_tbl = $wpdb->prefix . 'n88_supplier_materials';

        dbDelta(
            "CREATE TABLE {$supplier_media_table} (
                id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
                supplier_id BIGINT UNSIGNED NOT NULL,
                media_type VARCHAR(20) NOT NULL DEFAULT 'image',
                media_url TEXT NOT NULL,
                thumbnail_url TEXT NULL,
                attachment_id BIGINT UNSIGNED NULL,
                title VARCHAR(255) NULL,
                description TEXT NULL,
                tags LONGTEXT NULL,
                created_at DATETIME NOT NULL,
                updated_at DATETIME NOT NULL,
                is_active TINYINT(1) NOT NULL DEFAULT 1,
                PRIMARY KEY (id),
                KEY idx_supplier_active (supplier_id, is_active),
                KEY idx_supplier_media_type (supplier_id, media_type)
            ) {$charset_collate};"
        );

        dbDelta(
            "CREATE TABLE {$supplier_materials_tbl} (
                id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
                supplier_id BIGINT UNSIGNED NOT NULL,
                material_type VARCHAR(100) NOT NULL,
                material_name VARCHAR(255) NOT NULL,
                material_image_url TEXT NOT NULL,
                attachment_id BIGINT UNSIGNED NULL,
                material_code VARCHAR(100) NULL,
                description TEXT NULL,
                tags LONGTEXT NULL,
                created_at DATETIME NOT NULL,
                updated_at DATETIME NOT NULL,
                is_active TINYINT(1) NOT NULL DEFAULT 1,
                PRIMARY KEY (id),
                KEY idx_supplier_active (supplier_id, is_active),
                KEY idx_supplier_material_type (supplier_id, material_type)
            ) {$charset_collate};"
        );

        $media_library_support_ready = true;
    }

    private function current_user_can_manage_supplier_library() {
        if ( ! is_user_logged_in() ) {
            return false;
        }

        $current_user = wp_get_current_user();
        return in_array( 'n88_supplier_admin', (array) $current_user->roles, true );
    }

    private function normalize_supplier_library_tags( $raw_tags ) {
        if ( is_array( $raw_tags ) ) {
            $raw_tags = implode( ',', $raw_tags );
        }

        $tags = preg_split( '/[\r\n,]+/', (string) $raw_tags );
        $tags = array_filter(
            array_map(
                static function( $tag ) {
                    return sanitize_text_field( trim( $tag ) );
                },
                (array) $tags
            )
        );

        return array_values( array_unique( $tags ) );
    }

    private function upload_supplier_library_image( $file, $title_prefix ) {
        if ( empty( $file['name'] ) ) {
            return new WP_Error( 'missing_file', 'No file uploaded.' );
        }

        $upload = wp_handle_upload(
            $file,
            array(
                'test_form' => false,
                'mimes'     => array(
                    'jpg'  => 'image/jpeg',
                    'jpeg' => 'image/jpeg',
                    'png'  => 'image/png',
                    'webp' => 'image/webp',
                    'gif'  => 'image/gif',
                    'heic' => 'image/heic',
                    'heif' => 'image/heif',
                ),
            )
        );

        if ( ! empty( $upload['error'] ) ) {
            return new WP_Error( 'upload_failed', $upload['error'] );
        }

        $attachment_id = wp_insert_attachment(
            array(
                'post_mime_type' => $upload['type'],
                'post_title'     => sanitize_text_field( $title_prefix . ' - ' . wp_basename( $upload['file'] ) ),
                'post_content'   => '',
                'post_status'    => 'inherit',
            ),
            $upload['file']
        );

        if ( is_wp_error( $attachment_id ) ) {
            return $attachment_id;
        }

        $attach_data = wp_generate_attachment_metadata( $attachment_id, $upload['file'] );
        if ( ! empty( $attach_data ) ) {
            wp_update_attachment_metadata( $attachment_id, $attach_data );
        }

        $image_url = wp_get_attachment_url( $attachment_id );
        if ( ! $image_url ) {
            return new WP_Error( 'upload_missing_url', 'Image uploaded but URL could not be resolved.' );
        }

        return array(
            'attachment_id' => (int) $attachment_id,
            'url'           => esc_url_raw( $image_url ),
            'thumbnail_url' => esc_url_raw( wp_get_attachment_image_url( $attachment_id, 'medium' ) ?: $image_url ),
        );
    }

    private function format_supplier_media_library_item( $row ) {
        if ( ! is_array( $row ) ) {
            return array();
        }

        $tags = array();
        if ( ! empty( $row['tags'] ) ) {
            $decoded_tags = json_decode( (string) $row['tags'], true );
            if ( is_array( $decoded_tags ) ) {
                $tags = array_values( array_filter( array_map( 'sanitize_text_field', $decoded_tags ) ) );
            }
        }

        return array(
            'id'            => isset( $row['id'] ) ? (int) $row['id'] : 0,
            'media_type'    => isset( $row['media_type'] ) ? sanitize_key( $row['media_type'] ) : 'image',
            'media_url'     => isset( $row['media_url'] ) ? esc_url_raw( $row['media_url'] ) : '',
            'thumbnail_url' => isset( $row['thumbnail_url'] ) ? esc_url_raw( $row['thumbnail_url'] ) : '',
            'attachment_id' => isset( $row['attachment_id'] ) ? (int) $row['attachment_id'] : 0,
            'title'         => isset( $row['title'] ) ? sanitize_text_field( $row['title'] ) : '',
            'description'   => isset( $row['description'] ) ? sanitize_textarea_field( $row['description'] ) : '',
            'tags'          => $tags,
            'is_active'     => ! empty( $row['is_active'] ),
            'created_at'    => isset( $row['created_at'] ) ? $row['created_at'] : null,
            'updated_at'    => isset( $row['updated_at'] ) ? $row['updated_at'] : null,
        );
    }

    private function format_supplier_material_library_item( $row ) {
        if ( ! is_array( $row ) ) {
            return array();
        }

        $tags = array();
        if ( ! empty( $row['tags'] ) ) {
            $decoded_tags = json_decode( (string) $row['tags'], true );
            if ( is_array( $decoded_tags ) ) {
                $tags = array_values( array_filter( array_map( 'sanitize_text_field', $decoded_tags ) ) );
            }
        }

        return array(
            'id'                 => isset( $row['id'] ) ? (int) $row['id'] : 0,
            'material_id'        => isset( $row['id'] ) ? (int) $row['id'] : 0,
            'material_type'      => isset( $row['material_type'] ) ? sanitize_text_field( $row['material_type'] ) : '',
            'material_name'      => isset( $row['material_name'] ) ? sanitize_text_field( $row['material_name'] ) : '',
            'material_image_url' => isset( $row['material_image_url'] ) ? esc_url_raw( $row['material_image_url'] ) : '',
            'attachment_id'      => isset( $row['attachment_id'] ) ? (int) $row['attachment_id'] : 0,
            'material_code'      => isset( $row['material_code'] ) ? sanitize_text_field( $row['material_code'] ) : '',
            'description'        => isset( $row['description'] ) ? sanitize_textarea_field( $row['description'] ) : '',
            'tags'               => $tags,
            'is_active'          => ! empty( $row['is_active'] ),
            'created_at'         => isset( $row['created_at'] ) ? $row['created_at'] : null,
            'updated_at'         => isset( $row['updated_at'] ) ? $row['updated_at'] : null,
        );
    }

    private function get_supplier_media_library_payload( $supplier_id, $include_inactive = false ) {
        global $wpdb;

        $this->ensure_supplier_media_library_support();

        $supplier_id = absint( $supplier_id );
        if ( ! $supplier_id ) {
            return array(
                'our_work'         => array(),
                'material_samples' => array(),
            );
        }

        $media_table      = $wpdb->prefix . 'n88_supplier_media';
        $materials_table  = $wpdb->prefix . 'n88_supplier_materials';
        $active_condition = $include_inactive ? '' : ' AND is_active = 1';

        $portfolio_rows = $wpdb->get_results(
            $wpdb->prepare(
                "SELECT * FROM {$media_table} WHERE supplier_id = %d{$active_condition} ORDER BY is_active DESC, updated_at DESC, id DESC",
                $supplier_id
            ),
            ARRAY_A
        );

        $material_rows = $wpdb->get_results(
            $wpdb->prepare(
                "SELECT * FROM {$materials_table} WHERE supplier_id = %d{$active_condition} ORDER BY is_active DESC, updated_at DESC, id DESC",
                $supplier_id
            ),
            ARRAY_A
        );

        return array(
            'our_work'         => array_map( array( $this, 'format_supplier_media_library_item' ), (array) $portfolio_rows ),
            'material_samples' => array_map( array( $this, 'format_supplier_material_library_item' ), (array) $material_rows ),
        );
    }

    private function get_selected_supplier_material_library_items( $supplier_id, $material_refs = array(), $material_ids = array() ) {
        $selected_refs = array();
        foreach ( (array) $material_refs as $raw_ref ) {
            $raw_ref = sanitize_text_field( $raw_ref );
            if ( ! preg_match( '/^(our_work|material_samples):(\d+)$/', $raw_ref, $matches ) ) {
                continue;
            }
            $selected_refs[] = $matches[1] . ':' . absint( $matches[2] );
        }
        $selected_refs = array_values( array_unique( array_filter( $selected_refs ) ) );
        $selected_ids  = array_values( array_unique( array_filter( array_map( 'absint', (array) $material_ids ) ) ) );

        if ( ! $supplier_id || ( empty( $selected_refs ) && empty( $selected_ids ) ) ) {
            return array();
        }

        $payload       = $this->get_supplier_media_library_payload( $supplier_id, false );
        $library_index = array();
        $legacy_index  = array();

        foreach ( (array) $payload['our_work'] as $entry ) {
            $entry_id = isset( $entry['id'] ) ? absint( $entry['id'] ) : 0;
            if ( $entry_id ) {
                $normalized_entry = array_merge(
                    $entry,
                    array(
                        'library_group' => 'our_work',
                    )
                );
                $library_index[ 'our_work:' . $entry_id ] = $normalized_entry;
                if ( ! isset( $legacy_index[ $entry_id ] ) ) {
                    $legacy_index[ $entry_id ] = $normalized_entry;
                }
            }
        }

        foreach ( (array) $payload['material_samples'] as $entry ) {
            $entry_id = isset( $entry['material_id'] ) ? absint( $entry['material_id'] ) : ( isset( $entry['id'] ) ? absint( $entry['id'] ) : 0 );
            if ( $entry_id ) {
                $normalized_entry = array_merge(
                    $entry,
                    array(
                        'library_group' => 'material_samples',
                    )
                );
                $library_index[ 'material_samples:' . $entry_id ] = $normalized_entry;
                $legacy_index[ $entry_id ] = $normalized_entry;
            }
        }

        $selected_entries = array();
        if ( ! empty( $selected_refs ) ) {
            foreach ( $selected_refs as $selected_ref ) {
                if ( isset( $library_index[ $selected_ref ] ) ) {
                    $selected_entries[] = $library_index[ $selected_ref ];
                }
            }
            return $selected_entries;
        }

        foreach ( $selected_ids as $selected_id ) {
            if ( isset( $legacy_index[ $selected_id ] ) ) {
                $selected_entries[] = $legacy_index[ $selected_id ];
            }
        }

        return $selected_entries;
    }

