            .n88-supplier-media-meta-actions button, .n88-supplier-media-meta-actions a { padding:6px 10px; border-radius:999px; border:1px solid #555; background:#222; color:#fff; text-decoration:none; font-size:10px; cursor:pointer; }
            .n88-supplier-media-meta-actions .is-inactive { border-color:#ff9800; color:#ff9800; }
            .n88-supplier-media-library-feedback { margin-top:14px; padding:10px 12px; border-radius:10px; font-size:12px; }
            .n88-supplier-media-library-feedback.is-success { display:block !important; background:rgba(46,125,50,.15); border:1px solid #2e7d32; color:#7fd488; }
            .n88-supplier-media-library-feedback.is-error { display:block !important; background:rgba(198,40,40,.15); border:1px solid #c62828; color:#ff8f8f; }
            .n88-supplier-media-library-feedback.is-loading { display:block !important; background:rgba(255,255,255,.08); border:1px solid #666; color:#fff; }
        </style>
        <script>
        (function() {
            var libraries = document.querySelectorAll('.n88-supplier-media-library');
            var root = libraries[libraries.length - 1];
            if (!root || root.dataset.bound === '1') return;
            root.dataset.bound = '1';

            var ajaxUrl = root.getAttribute('data-ajax-url');
            var nonce = root.getAttribute('data-nonce');
            var feedback = root.querySelector('.n88-supplier-media-library-feedback');

            function showFeedback(message, state) {
                if (!feedback) return;
                feedback.textContent = message || '';
                if (!message) {
                    feedback.className = 'n88-supplier-media-library-feedback';
                    feedback.style.display = 'none';
                    return;
                }
                feedback.className = 'n88-supplier-media-library-feedback ' + (state || 'is-success');
            }

            function escapeHtml(value) {
                return String(value || '').replace(/[&<>\"']/g, function(m) {
                    return ({ '&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;', "'":'&#039;' })[m];
                });
            }

            function setButtonLoading(button, isLoading, loadingText) {
                if (!button) return;
                if (!button.dataset.idleText) {
                    button.dataset.idleText = button.textContent;
                }
                button.disabled = !!isLoading;
                button.textContent = isLoading ? (loadingText || 'Saving...') : button.dataset.idleText;
            }

            function renderList(group, items) {
                var list = root.querySelector('[data-library-list=\"' + group + '\"]');
                if (!list) return;
                if (!items || !items.length) {
                    list.innerHTML = '<div class=\"n88-supplier-media-card\"><div class=\"n88-supplier-media-meta\" style=\"grid-column:1 / -1;\"><h5>No items yet</h5><p>Add assets here so designers can review your work and reusable materials later.</p></div></div>';
                    return;
                }

                list.innerHTML = items.map(function(item) {
                    var thumb = group === 'our_work' ? (item.thumbnail_url || item.media_url || '') : (item.material_image_url || '');
                    var title = group === 'our_work' ? (item.title || (item.media_type === 'video' ? 'Video Asset' : 'Image Asset')) : (item.material_name || 'Material Sample');
                    var subtitle = group === 'our_work' ? (item.description || '') : [item.material_type || '', item.material_code || '', item.description || ''].filter(Boolean).join(' | ');
                    var tags = Array.isArray(item.tags) ? item.tags : [];
                    var href = group === 'our_work' ? (item.media_url || '#') : (item.material_image_url || '#');
                    var isVideo = group === 'our_work' && item.media_type === 'video';
                    var payload = encodeURIComponent(JSON.stringify(item));

                    return '<div class=\"n88-supplier-media-card\"><div class=\"n88-supplier-media-thumb\">' + (thumb ? '<img loading=\"lazy\" src=\"' + escapeHtml(thumb) + '\" alt=\"\">' : '<span>[media]</span>') + (isVideo ? '<span class=\"n88-play\">&#9654;</span>' : '') + '</div><div class=\"n88-supplier-media-meta\"><h5>' + escapeHtml(title) + '</h5><p>' + escapeHtml(subtitle) + '</p><div class=\"n88-supplier-media-tags\">' + tags.map(function(tag) { return '<span>' + escapeHtml(tag) + '</span>'; }).join('') + '</div><div class=\"n88-supplier-media-meta-actions\"><a href=\"' + escapeHtml(href) + '\" target=\"_blank\" rel=\"noopener noreferrer\">Open</a><button type=\"button\" data-action=\"edit\" data-group=\"' + escapeHtml(group) + '\" data-payload=\"' + payload + '\">Edit</button><button type=\"button\" class=\"' + (!item.is_active ? 'is-inactive' : '') + '\" data-action=\"toggle\" data-group=\"' + escapeHtml(group) + '\" data-id=\"' + escapeHtml(group === 'our_work' ? item.id : (item.material_id || item.id)) + '\" data-next-state=\"' + (item.is_active ? '0' : '1') + '\">' + (item.is_active ? 'Disable' : 'Enable') + '</button></div></div></div>';
                }).join('');
            }

            function refreshLibrary() {
                var fd = new FormData();
                fd.append('action', 'n88_get_supplier_media_library');
                fd.append('nonce', nonce);

                return fetch(ajaxUrl, { method:'POST', body:fd }).then(function(r) {
                    return r.json();
                }).then(function(data) {
                    if (!data || !data.success || !data.data) {
                        throw new Error((data && data.data && data.data.message) ? data.data.message : 'Failed to load media library.');
                    }
                    renderList('our_work', data.data.our_work || []);
                    renderList('material_samples', data.data.material_samples || []);
                    return data.data;
                }).catch(function(err) {
                    showFeedback(err && err.message ? err.message : 'Failed to load media library.', 'is-error');
                    throw err;
                });
            }

            root.querySelectorAll('[data-library-list]').forEach(function(list) {
                var items = [];
                try { items = JSON.parse(list.getAttribute('data-items') || '[]'); } catch (err) {}
                renderList(list.getAttribute('data-library-list'), items);
            });

            root.querySelectorAll('.n88-supplier-media-form').forEach(function(form) {
                var mediaTypeSelect = form.querySelector('select[name=\"media_type\"]');
                var submitButton = form.querySelector('.n88-supplier-media-submit');

                function syncMediaFields() {
                    if (!mediaTypeSelect) return;
                    var isVideo = mediaTypeSelect.value === 'video';
                    form.querySelectorAll('.n88-media-video-field').forEach(function(node) { node.style.display = isVideo ? '' : 'none'; });
                    form.querySelectorAll('.n88-media-file-field').forEach(function(node) {
                        if (form.getAttribute('data-library-group') === 'our_work') {
                            node.style.display = isVideo ? 'none' : '';
                        }
                    });
                }

                if (mediaTypeSelect) {
                    mediaTypeSelect.addEventListener('change', syncMediaFields);
                    syncMediaFields();
                }

                form.addEventListener('submit', function(event) {
                    event.preventDefault();

                    var fd = new FormData(form);
                    fd.append('action', 'n88_save_supplier_media_asset');
                    fd.append('nonce', nonce);
                    fd.append('library_group', form.getAttribute('data-library-group') || '');

                    setButtonLoading(submitButton, true, 'Uploading...');
                    showFeedback('Uploading asset...', 'is-loading');

                    fetch(ajaxUrl, { method:'POST', body:fd }).then(function(r) {
                        return r.json();
                    }).then(function(data) {
                        if (!data || !data.success) {
                            throw new Error((data && data.data && data.data.message) ? data.data.message : 'Failed to save media asset.');
                        }

                        form.reset();
                        syncMediaFields();

                        return refreshLibrary().then(function() {
                            showFeedback((data.data && data.data.message) ? data.data.message : 'Saved successfully.', 'is-success');
                        });
                    }).catch(function(err) {
                        showFeedback(err && err.message ? err.message : 'Failed to save media asset.', 'is-error');
                    }).finally(function() {
                        setButtonLoading(submitButton, false);
                    });
                });
            });

            root.addEventListener('click', function(event) {
                var button = event.target.closest('button[data-action]');
                if (!button) return;

                var action = button.getAttribute('data-action');
                var group = button.getAttribute('data-group') || '';

                if (action === 'toggle') {
                    var toggleData = new FormData();
                    toggleData.append('action', 'n88_toggle_supplier_media_asset');
                    toggleData.append('nonce', nonce);
                    toggleData.append('library_group', group);
                    toggleData.append('record_id', button.getAttribute('data-id') || '');
                    toggleData.append('is_active', button.getAttribute('data-next-state') || '0');

                    showFeedback('Updating asset...', 'is-loading');

                    fetch(ajaxUrl, { method:'POST', body:toggleData }).then(function(r) {
                        return r.json();
                    }).then(function(data) {
                        if (!data || !data.success) {
                            throw new Error((data && data.data && data.data.message) ? data.data.message : 'Failed to update asset.');
                        }

                        return refreshLibrary().then(function() {
                            showFeedback((data.data && data.data.message) ? data.data.message : 'Updated successfully.', 'is-success');
                        });
                    }).catch(function(err) {
                        showFeedback(err && err.message ? err.message : 'Failed to update asset.', 'is-error');
                    });
                    return;
                }

                if (action === 'edit') {
                    var payload = {};
                    try { payload = JSON.parse(decodeURIComponent(button.getAttribute('data-payload') || '{}')); } catch (err) {}

                    var editData = new FormData();
                    editData.append('action', 'n88_update_supplier_media_asset');
                    editData.append('nonce', nonce);
                    editData.append('library_group', group);
                    editData.append('record_id', payload.material_id || payload.id || '');

                    if (group === 'our_work') {
                        var title = window.prompt('Title', payload.title || '');
                        if (title === null) return;
                        var description = window.prompt('Description', payload.description || '');
                        if (description === null) return;
                        var tags = window.prompt('Tags (comma separated)', (payload.tags || []).join(', '));
                        if (tags === null) return;

                        editData.append('title', title);
                        editData.append('description', description);
                        editData.append('tags', tags);
                    } else {
                        var materialName = window.prompt('Material Name', payload.material_name || '');
                        if (materialName === null) return;
                        var materialType = window.prompt('Material Type', payload.material_type || '');
                        if (materialType === null) return;
                        var materialCode = window.prompt('Material Code', payload.material_code || '');
                        if (materialCode === null) return;
                        var materialDesc = window.prompt('Description', payload.description || '');
                        if (materialDesc === null) return;
                        var materialTags = window.prompt('Tags (comma separated)', (payload.tags || []).join(', '));
                        if (materialTags === null) return;

                        editData.append('material_name', materialName);
                        editData.append('material_type', materialType);
                        editData.append('material_code', materialCode);
                        editData.append('description', materialDesc);
                        editData.append('tags', materialTags);
                    }

                    showFeedback('Saving changes...', 'is-loading');

                    fetch(ajaxUrl, { method:'POST', body:editData }).then(function(r) {
                        return r.json();
                    }).then(function(data) {
                        if (!data || !data.success) {
                            throw new Error((data && data.data && data.data.message) ? data.data.message : 'Failed to update asset.');
                        }

                        return refreshLibrary().then(function() {
                            showFeedback((data.data && data.data.message) ? data.data.message : 'Updated successfully.', 'is-success');
                        });
                    }).catch(function(err) {
                        showFeedback(err && err.message ? err.message : 'Failed to update asset.', 'is-error');
                    });
                }
            });
        })();
        </script>
        <?php

        return ob_get_clean();
    }

    public function ajax_get_supplier_media_library() {
        check_ajax_referer( 'n88_supplier_media_library', 'nonce' );

        if ( ! is_user_logged_in() ) {
            wp_send_json_error( array( 'message' => 'Authentication required.' ), 401 );
        }

        $current_user = wp_get_current_user();
        $requested_supplier_id = absint( isset( $_POST['supplier_id'] ) ? wp_unslash( $_POST['supplier_id'] ) : 0 );
        $target_supplier_id    = $requested_supplier_id ? $requested_supplier_id : get_current_user_id();
        $is_supplier_self      = in_array( 'n88_supplier_admin', (array) $current_user->roles, true ) && $target_supplier_id === get_current_user_id();
        $can_read_other        = current_user_can( 'manage_options' ) || in_array( 'n88_system_operator', (array) $current_user->roles, true ) || in_array( 'n88_designer', (array) $current_user->roles, true ) || in_array( 'designer', (array) $current_user->roles, true );

        if ( ! $is_supplier_self && ! $can_read_other ) {
            wp_send_json_error( array( 'message' => 'Access denied.' ), 403 );
        }

        wp_send_json_success( $this->get_supplier_media_library_payload( $target_supplier_id, $is_supplier_self ) );
    }

    public function ajax_save_supplier_media_asset() {
        check_ajax_referer( 'n88_supplier_media_library', 'nonce' );

        if ( ! $this->current_user_can_manage_supplier_library() ) {
            wp_send_json_error( array( 'message' => 'Access denied.' ), 403 );
        }

        global $wpdb;

        $this->ensure_supplier_media_library_support();

        $supplier_id      = get_current_user_id();
        $library_group    = sanitize_key( isset( $_POST['library_group'] ) ? wp_unslash( $_POST['library_group'] ) : '' );
        $media_table      = $wpdb->prefix . 'n88_supplier_media';
        $materials_table  = $wpdb->prefix . 'n88_supplier_materials';
        $timestamp        = current_time( 'mysql' );

        if ( 'our_work' === $library_group ) {
            $media_type    = sanitize_key( isset( $_POST['media_type'] ) ? wp_unslash( $_POST['media_type'] ) : 'image' );
            $title         = sanitize_text_field( isset( $_POST['title'] ) ? wp_unslash( $_POST['title'] ) : '' );
            $description   = sanitize_textarea_field( isset( $_POST['description'] ) ? wp_unslash( $_POST['description'] ) : '' );
            $tags          = wp_json_encode( $this->normalize_supplier_library_tags( isset( $_POST['tags'] ) ? wp_unslash( $_POST['tags'] ) : '' ) );
            $media_url     = '';
            $thumbnail_url = '';
            $attachment_id = null;

            if ( 'video' === $media_type ) {
                $media_url     = esc_url_raw( isset( $_POST['video_url'] ) ? wp_unslash( $_POST['video_url'] ) : '' );
                $thumbnail_url = esc_url_raw( isset( $_POST['thumbnail_url'] ) ? wp_unslash( $_POST['thumbnail_url'] ) : '' );
                if ( ! $media_url || ! $thumbnail_url ) {
                    wp_send_json_error( array( 'message' => 'Video URL and thumbnail URL are required.' ), 400 );
                }
            } else {
                if ( empty( $_FILES['image_file'] ) || empty( $_FILES['image_file']['name'] ) ) {
                    wp_send_json_error( array( 'message' => 'Please upload an image for Our Work.' ), 400 );
                }

                $upload = $this->upload_supplier_library_image( $_FILES['image_file'], 'Supplier Work Media ' . $supplier_id );
                if ( is_wp_error( $upload ) ) {
                    wp_send_json_error( array( 'message' => $upload->get_error_message() ), 400 );
                }

                $media_url     = $upload['url'];
                $thumbnail_url = $upload['thumbnail_url'];
                $attachment_id = $upload['attachment_id'];
            }

            $wpdb->insert(
                $media_table,
                array(
                    'supplier_id'   => $supplier_id,
                    'media_type'    => $media_type,
                    'media_url'     => $media_url,
                    'thumbnail_url' => $thumbnail_url,
                    'attachment_id' => $attachment_id,
                    'title'         => $title,
                    'description'   => $description,
                    'tags'          => $tags,
                    'created_at'    => $timestamp,
                    'updated_at'    => $timestamp,
                    'is_active'     => 1,
                ),
                array( '%d', '%s', '%s', '%s', '%d', '%s', '%s', '%s', '%s', '%s', '%d' )
            );

            if ( ! $wpdb->insert_id ) {
                wp_send_json_error( array( 'message' => 'Failed to save portfolio media.' ), 500 );
            }

            wp_send_json_success( array( 'message' => 'Our Work asset saved.' ) );
        }

        if ( 'material_samples' === $library_group ) {
            $material_type = sanitize_text_field( isset( $_POST['material_type'] ) ? wp_unslash( $_POST['material_type'] ) : '' );
            $material_name = sanitize_text_field( isset( $_POST['material_name'] ) ? wp_unslash( $_POST['material_name'] ) : '' );
            $material_code = sanitize_text_field( isset( $_POST['material_code'] ) ? wp_unslash( $_POST['material_code'] ) : '' );
            $description   = sanitize_textarea_field( isset( $_POST['description'] ) ? wp_unslash( $_POST['description'] ) : '' );
            $tags          = wp_json_encode( $this->normalize_supplier_library_tags( isset( $_POST['tags'] ) ? wp_unslash( $_POST['tags'] ) : '' ) );

            if ( '' === $material_type || '' === $material_name ) {
                wp_send_json_error( array( 'message' => 'Material type and name are required.' ), 400 );
            }

            if ( empty( $_FILES['material_image_file'] ) || empty( $_FILES['material_image_file']['name'] ) ) {
                wp_send_json_error( array( 'message' => 'Please upload a material sample image.' ), 400 );
            }

            $upload = $this->upload_supplier_library_image( $_FILES['material_image_file'], 'Supplier Material Sample ' . $supplier_id );
            if ( is_wp_error( $upload ) ) {
                wp_send_json_error( array( 'message' => $upload->get_error_message() ), 400 );
            }

            $wpdb->insert(
                $materials_table,
                array(
                    'supplier_id'        => $supplier_id,
                    'material_type'      => $material_type,
                    'material_name'      => $material_name,
                    'material_image_url' => $upload['url'],
                    'attachment_id'      => $upload['attachment_id'],
                    'material_code'      => $material_code,
                    'description'        => $description,
                    'tags'               => $tags,
                    'created_at'         => $timestamp,
                    'updated_at'         => $timestamp,
                    'is_active'          => 1,
                ),
                array( '%d', '%s', '%s', '%s', '%d', '%s', '%s', '%s', '%s', '%s', '%d' )
            );

            if ( ! $wpdb->insert_id ) {
                wp_send_json_error( array( 'message' => 'Failed to save material sample.' ), 500 );
            }

            wp_send_json_success( array( 'message' => 'Material sample saved.' ) );
        }

        wp_send_json_error( array( 'message' => 'Unknown media library section.' ), 400 );
    }

    public function ajax_update_supplier_media_asset() {
        check_ajax_referer( 'n88_supplier_media_library', 'nonce' );

        if ( ! $this->current_user_can_manage_supplier_library() ) {
            wp_send_json_error( array( 'message' => 'Access denied.' ), 403 );
        }

        global $wpdb;

        $this->ensure_supplier_media_library_support();

        $supplier_id     = get_current_user_id();
        $library_group   = sanitize_key( isset( $_POST['library_group'] ) ? wp_unslash( $_POST['library_group'] ) : '' );
        $record_id       = absint( isset( $_POST['record_id'] ) ? wp_unslash( $_POST['record_id'] ) : 0 );
        $timestamp       = current_time( 'mysql' );
        $media_table     = $wpdb->prefix . 'n88_supplier_media';
        $materials_table = $wpdb->prefix . 'n88_supplier_materials';

        if ( ! $record_id ) {
            wp_send_json_error( array( 'message' => 'Invalid record selected.' ), 400 );
        }

        if ( 'our_work' === $library_group ) {
            $updated = $wpdb->update(
                $media_table,
                array(
                    'title'       => sanitize_text_field( isset( $_POST['title'] ) ? wp_unslash( $_POST['title'] ) : '' ),
                    'description' => sanitize_textarea_field( isset( $_POST['description'] ) ? wp_unslash( $_POST['description'] ) : '' ),
                    'tags'        => wp_json_encode( $this->normalize_supplier_library_tags( isset( $_POST['tags'] ) ? wp_unslash( $_POST['tags'] ) : '' ) ),
                    'updated_at'  => $timestamp,
                ),
                array( 'id' => $record_id, 'supplier_id' => $supplier_id ),
                array( '%s', '%s', '%s', '%s' ),
                array( '%d', '%d' )
            );

            if ( false === $updated ) {
                wp_send_json_error( array( 'message' => 'Failed to update portfolio media.' ), 500 );
            }

            wp_send_json_success( array( 'message' => 'Our Work asset updated.' ) );
        }

        if ( 'material_samples' === $library_group ) {
            $updated = $wpdb->update(
                $materials_table,
                array(
                    'material_type' => sanitize_text_field( isset( $_POST['material_type'] ) ? wp_unslash( $_POST['material_type'] ) : '' ),
                    'material_name' => sanitize_text_field( isset( $_POST['material_name'] ) ? wp_unslash( $_POST['material_name'] ) : '' ),
                    'material_code' => sanitize_text_field( isset( $_POST['material_code'] ) ? wp_unslash( $_POST['material_code'] ) : '' ),
                    'description'   => sanitize_textarea_field( isset( $_POST['description'] ) ? wp_unslash( $_POST['description'] ) : '' ),
                    'tags'          => wp_json_encode( $this->normalize_supplier_library_tags( isset( $_POST['tags'] ) ? wp_unslash( $_POST['tags'] ) : '' ) ),
                    'updated_at'    => $timestamp,
                ),
                array( 'id' => $record_id, 'supplier_id' => $supplier_id ),
                array( '%s', '%s', '%s', '%s', '%s', '%s' ),
                array( '%d', '%d' )
            );

            if ( false === $updated ) {
                wp_send_json_error( array( 'message' => 'Failed to update material sample.' ), 500 );
            }

            wp_send_json_success( array( 'message' => 'Material sample updated.' ) );
        }

        wp_send_json_error( array( 'message' => 'Unknown media library section.' ), 400 );
    }

    public function ajax_toggle_supplier_media_asset() {
        check_ajax_referer( 'n88_supplier_media_library', 'nonce' );

        if ( ! $this->current_user_can_manage_supplier_library() ) {
            wp_send_json_error( array( 'message' => 'Access denied.' ), 403 );
        }

        global $wpdb;

        $this->ensure_supplier_media_library_support();

        $supplier_id   = get_current_user_id();
        $library_group = sanitize_key( isset( $_POST['library_group'] ) ? wp_unslash( $_POST['library_group'] ) : '' );
        $record_id     = absint( isset( $_POST['record_id'] ) ? wp_unslash( $_POST['record_id'] ) : 0 );
        $is_active     = isset( $_POST['is_active'] ) ? absint( $_POST['is_active'] ) : 0;
        $timestamp     = current_time( 'mysql' );
        $table_name    = 'material_samples' === $library_group ? $wpdb->prefix . 'n88_supplier_materials' : $wpdb->prefix . 'n88_supplier_media';

        if ( ! $record_id ) {
            wp_send_json_error( array( 'message' => 'Invalid record selected.' ), 400 );
        }

        $updated = $wpdb->update(
            $table_name,
            array(
                'is_active'  => $is_active ? 1 : 0,
                'updated_at' => $timestamp,
            ),
            array( 'id' => $record_id, 'supplier_id' => $supplier_id ),
            array( '%d', '%s' ),
            array( '%d', '%d' )
        );

        if ( false === $updated ) {
            wp_send_json_error( array( 'message' => 'Failed to update media library asset.' ), 500 );
        }

        wp_send_json_success( array( 'message' => $is_active ? 'Asset enabled.' : 'Asset disabled.' ) );
    }

    /**
     * Commit 3.C.20: Normalize supported thread context keys.
     *
     * @param string $raw_context Raw context.
     * @return string
     */
    private function normalize_item_message_context_type( $raw_context ) {
        $context_type = sanitize_key( (string) $raw_context );
        $allowed      = array(
            'item_specs',
            'batch_proposal',
            'step_1_responses',
            'step_2_validation',
            'step_3_commitment',
            'step_4_production',
            'step_5_quality',
            'step_6_delivery',
        );

        return in_array( $context_type, $allowed, true ) ? $context_type : '';
    }

    /**
     * Map unified message context keys to supplier/designer workflow step indexes.
     *
     * @param string $context_type Message context key.
     * @return int|null
     */
    private function get_item_message_context_step_index( $context_type ) {
        $normalized = $this->normalize_item_message_context_type( $context_type );
        $map        = array(
            'step_1_responses'  => 0,
            'step_2_validation' => 1,
            'step_3_commitment' => 2,
            'step_4_production' => 3,
            'step_5_quality'    => 4,
            'step_6_delivery'   => 5,
        );

        return isset( $map[ $normalized ] ) ? $map[ $normalized ] : null;
    }

    /**
     * Repair or normalize direct designer <-> supplier messages so retrieval stays stable.
     *
     * Older installs could save blank thread_type or missing designer/supplier context before
     * the messaging schema was expanded. This method force-normalizes those rows.
     *
     * @param int $item_id Item ID.
     * @param int $supplier_id Supplier user ID.
     * @param int $designer_id Designer user ID.
     * @param int $message_id Optional specific message ID to normalize.
     * @return void
     */
    private function repair_designer_supplier_thread_messages( $item_id, $supplier_id, $designer_id, $message_id = 0 ) {
        global $wpdb;

        $item_id     = absint( $item_id );
        $supplier_id = absint( $supplier_id );
        $designer_id = absint( $designer_id );
        $message_id  = absint( $message_id );

        if ( ! $item_id || ! $supplier_id || ! $designer_id ) {
            return;
        }

        $messages_table = $wpdb->prefix . 'n88_item_messages';

        if ( $message_id ) {
            $wpdb->update(
                $messages_table,
                array(
                    'thread_type' => 'designer_supplier',
                    'supplier_id' => $supplier_id,
                    'designer_id' => $designer_id,
                ),
                array( 'message_id' => $message_id ),
                array( '%s', '%d', '%d' ),
                array( '%d' )
            );
        }

        $wpdb->query(
            $wpdb->prepare(
                "UPDATE {$messages_table}
                SET thread_type = 'designer_supplier',
                    supplier_id = %d,
                    designer_id = %d
                WHERE item_id = %d
                AND sender_role = 'designer'
                AND sender_user_id = %d
                AND (thread_type = 'designer_supplier' OR thread_type = '' OR thread_type IS NULL)
                AND (
                    supplier_id IS NULL OR supplier_id = 0
                    OR designer_id IS NULL OR designer_id = 0
                    OR thread_type = '' OR thread_type IS NULL
                )",
                $supplier_id,
                $designer_id,
                $item_id,
                $designer_id
            )
        );

        $wpdb->query(
            $wpdb->prepare(
                "UPDATE {$messages_table}
                SET thread_type = 'designer_supplier',
                    supplier_id = %d,
                    designer_id = %d
                WHERE item_id = %d
                AND sender_role = 'supplier'
                AND sender_user_id = %d
                AND (thread_type = 'designer_supplier' OR thread_type = '' OR thread_type IS NULL)
                AND (
                    supplier_id IS NULL OR supplier_id = 0
                    OR designer_id IS NULL OR designer_id = 0
                    OR thread_type = '' OR thread_type IS NULL
                )",
                $supplier_id,
                $designer_id,
                $item_id,
                $supplier_id
            )
        );
    }

    /**
     * Commit 3.C.14: Normalize incoming item IDs from AJAX.
     *
     * @param mixed $raw_ids Raw POST value.
     * @return array
     */
    private function normalize_supplier_batch_item_ids( $raw_ids ) {
        if ( is_string( $raw_ids ) ) {
            $decoded = json_decode( wp_unslash( $raw_ids ), true );
            if ( is_array( $decoded ) ) {
                $raw_ids = $decoded;
            } else {
                $raw_ids = array_filter( array_map( 'trim', explode( ',', $raw_ids ) ) );
            }
        }

        if ( ! is_array( $raw_ids ) ) {
            return array();
        }

        $item_ids = array_values( array_unique( array_filter( array_map( 'absint', $raw_ids ) ) ) );
        sort( $item_ids );
        return $item_ids;
    }

    /**
     * Commit 3.C.14: Build or fetch a proposal-group workspace for the supplier.
     *
     * @param int   $supplier_id Supplier user ID.
     * @param array $item_ids    Selected item IDs.
     * @return array|WP_Error
     */
    private function get_or_create_supplier_batch_workspace( $supplier_id, $item_ids ) {
        global $wpdb;

        $this->ensure_supplier_proposal_workspace_support();

        $supplier_id        = absint( $supplier_id );
        $item_ids           = $this->normalize_supplier_batch_item_ids( $item_ids );
        $items_table        = $wpdb->prefix . 'n88_items';
        $projects_table     = $wpdb->prefix . 'n88_projects';
        $groups_table       = $wpdb->prefix . 'n88_supplier_proposal_groups';
        $group_items_table  = $wpdb->prefix . 'n88_supplier_proposal_group_items';
        $group_uploads_table = $wpdb->prefix . 'n88_supplier_proposal_group_uploads';

        if ( ! $supplier_id || empty( $item_ids ) ) {
            return new WP_Error( 'invalid_batch_workspace', 'No valid RFQ items were provided.' );
        }

        $accessible_items = array();
        foreach ( $item_ids as $item_id ) {
            if ( ! $this->supplier_has_route_to_item( $item_id, $supplier_id ) ) {
                continue;
            }

            $item_row = $wpdb->get_row( $wpdb->prepare(
                "SELECT id, title, owner_user_id, project_id FROM {$items_table} WHERE id = %d AND deleted_at IS NULL",
                $item_id
            ), ARRAY_A );

            if ( $item_row ) {
                $accessible_items[] = $item_row;
            }
        }

        if ( empty( $accessible_items ) ) {
            return new WP_Error( 'no_accessible_items', 'No accessible RFQ items were found for this workspace.' );
        }

        $normalized_ids = array_map( 'intval', wp_list_pluck( $accessible_items, 'id' ) );
        sort( $normalized_ids );
        $workspace_key = md5( implode( ':', $normalized_ids ) );

        $group = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$groups_table} WHERE supplier_id = %d AND workspace_key = %s LIMIT 1",
            $supplier_id,
            $workspace_key
        ), ARRAY_A );

        $designer_ids = array_values( array_unique( array_filter( array_map( 'intval', wp_list_pluck( $accessible_items, 'owner_user_id' ) ) ) ) );
        $project_ids  = array_values( array_unique( array_filter( array_map( 'intval', wp_list_pluck( $accessible_items, 'project_id' ) ) ) ) );
        $designer_id  = count( $designer_ids ) === 1 ? $designer_ids[0] : 0;
        $project_id   = count( $project_ids ) === 1 ? $project_ids[0] : 0;

        $designer_label = 'Multiple Designers';
        if ( count( $designer_ids ) === 1 ) {
            $designer = get_userdata( $designer_ids[0] );
            $designer_label = $designer ? $designer->display_name : 'Designer #' . $designer_ids[0];
        }

        $project_label = 'Multiple Projects';
        if ( count( $project_ids ) === 1 ) {
            $project_label = $wpdb->get_var( $wpdb->prepare(
                "SELECT name FROM {$projects_table} WHERE id = %d LIMIT 1",
                $project_ids[0]
            ) );
            if ( ! $project_label ) {
                $project_label = 'Project #' . $project_ids[0];
            }
        }

        $workspace_label = count( $normalized_ids ) === 1 ? 'Single Item Proposal Workspace' : 'Multi-Item Proposal Workspace';
        $now             = current_time( 'mysql' );

        if ( ! $group ) {
            $wpdb->insert(
                $groups_table,
                array(
                    'supplier_id'     => $supplier_id,
                    'workspace_key'   => $workspace_key,
                    'workspace_label' => $workspace_label,
                    'designer_id'     => $designer_id ? $designer_id : null,
                    'project_id'      => $project_id ? $project_id : null,
                    'item_count'      => count( $normalized_ids ),
                    'status'          => 'draft',
                    'created_at'      => $now,
                    'updated_at'      => $now,
                ),
                array( '%d', '%s', '%s', '%d', '%d', '%d', '%s', '%s', '%s' )
            );

            $proposal_group_id = (int) $wpdb->insert_id;
            $rfq_reference     = 'RFQ-GROUP-' . $proposal_group_id;

            $wpdb->update(
                $groups_table,
                array(
                    'rfq_reference'   => $rfq_reference,
                    'workspace_label' => $workspace_label,
                    'designer_id'     => $designer_id ? $designer_id : null,
                    'project_id'      => $project_id ? $project_id : null,
                    'item_count'      => count( $normalized_ids ),
                    'updated_at'      => $now,
                ),
                array( 'proposal_group_id' => $proposal_group_id ),
                array( '%s', '%s', '%d', '%d', '%d', '%s' ),
                array( '%d' )
            );

            $group = $wpdb->get_row( $wpdb->prepare(
                "SELECT * FROM {$groups_table} WHERE proposal_group_id = %d LIMIT 1",
                $proposal_group_id
            ), ARRAY_A );
        } else {
            $proposal_group_id = (int) $group['proposal_group_id'];
            $rfq_reference     = ! empty( $group['rfq_reference'] ) ? $group['rfq_reference'] : 'RFQ-GROUP-' . $proposal_group_id;

            $wpdb->update(
                $groups_table,
                array(
                    'workspace_label' => $workspace_label,
                    'rfq_reference'   => $rfq_reference,
                    'designer_id'     => $designer_id ? $designer_id : null,
                    'project_id'      => $project_id ? $project_id : null,
                    'item_count'      => count( $normalized_ids ),
                    'updated_at'      => $now,
                ),
                array( 'proposal_group_id' => $proposal_group_id ),
                array( '%s', '%s', '%d', '%d', '%d', '%s' ),
                array( '%d' )
            );
        }

        $group_items_rows = $wpdb->get_results( $wpdb->prepare(
            "SELECT item_id, quote_decision, item_state, linked_bid_id FROM {$group_items_table} WHERE proposal_group_id = %d AND supplier_id = %d",
            $proposal_group_id,
            $supplier_id
        ), ARRAY_A );

        $existing_item_ids = array();
        foreach ( $group_items_rows as $row ) {
            $existing_item_ids[] = (int) $row['item_id'];
        }
        foreach ( $normalized_ids as $item_id ) {
            if ( ! in_array( (int) $item_id, $existing_item_ids, true ) ) {
                $this->upsert_supplier_batch_item_state( $proposal_group_id, $supplier_id, $item_id, 'quote', 'not_ready', null );
            }
        }
        if ( count( $existing_item_ids ) !== count( $normalized_ids ) ) {
            $group_items_rows = $wpdb->get_results( $wpdb->prepare(
                "SELECT item_id, quote_decision, item_state, linked_bid_id FROM {$group_items_table} WHERE proposal_group_id = %d AND supplier_id = %d",
                $proposal_group_id,
                $supplier_id
            ), ARRAY_A );
        }

        $group_items = array();
        foreach ( $group_items_rows as $row ) {
            $group_items[ (int) $row['item_id'] ] = array(
                'quote_decision' => ! empty( $row['quote_decision'] ) ? $row['quote_decision'] : 'quote',
                'item_state'     => ! empty( $row['item_state'] ) ? $row['item_state'] : 'not_ready',
                'linked_bid_id'  => ! empty( $row['linked_bid_id'] ) ? (int) $row['linked_bid_id'] : null,
            );
        }

        $shared_uploads_rows = $wpdb->get_results( $wpdb->prepare(
            "SELECT id, attachment_id, file_url, file_name, created_at FROM {$group_uploads_table} WHERE proposal_group_id = %d AND supplier_id = %d ORDER BY created_at ASC",
            $proposal_group_id,
            $supplier_id
        ), ARRAY_A );

        $shared_uploads = array();
        foreach ( $shared_uploads_rows as $upload ) {
            $shared_uploads[] = array(
                'id'            => (int) $upload['id'],
                'attachment_id' => ! empty( $upload['attachment_id'] ) ? (int) $upload['attachment_id'] : null,
                'file_url'      => esc_url_raw( $upload['file_url'] ),
                'file_name'     => sanitize_file_name( $upload['file_name'] ),
                'created_at'    => $upload['created_at'],
            );
        }

        return array(
            'proposal_group_id' => (int) $proposal_group_id,
            'rfq_reference'     => $rfq_reference,
            'workspace_label'   => $workspace_label,
            'designer_name'     => $designer_label,
            'project_name'      => $project_label,
            'item_ids'          => $normalized_ids,
            'item_count'        => count( $normalized_ids ),
            'item_states'       => $group_items,
            'shared_uploads'    => $shared_uploads,
        );
    }

    /**
     * Commit 3.C.14: Upsert supplier decision/state for an item in a proposal workspace.
     */
    private function upsert_supplier_batch_item_state( $proposal_group_id, $supplier_id, $item_id, $quote_decision = 'quote', $item_state = 'not_ready', $linked_bid_id = null ) {
        global $wpdb;

        $this->ensure_supplier_proposal_workspace_support();

        $proposal_group_id = absint( $proposal_group_id );
        $supplier_id       = absint( $supplier_id );
        $item_id           = absint( $item_id );
        $linked_bid_id     = $linked_bid_id ? absint( $linked_bid_id ) : null;
        $quote_decision    = in_array( $quote_decision, array( 'quote', 'skip' ), true ) ? $quote_decision : 'quote';
        $allowed_states    = array( 'quoted', 'ready', 'not_ready', 'not_quoted' );
        $item_state        = in_array( $item_state, $allowed_states, true ) ? $item_state : 'not_ready';

        if ( ! $proposal_group_id || ! $supplier_id || ! $item_id ) {
            return false;
        }

        $group_items_table = $wpdb->prefix . 'n88_supplier_proposal_group_items';
        $existing          = $wpdb->get_var( $wpdb->prepare(
            "SELECT id FROM {$group_items_table} WHERE proposal_group_id = %d AND supplier_id = %d AND item_id = %d LIMIT 1",
            $proposal_group_id,
            $supplier_id,
            $item_id
        ) );

        $payload = array(
            'proposal_group_id' => $proposal_group_id,
            'item_id'           => $item_id,
            'supplier_id'       => $supplier_id,
            'quote_decision'    => $quote_decision,
            'item_state'        => $item_state,
            'linked_bid_id'     => $linked_bid_id,
            'updated_at'        => current_time( 'mysql' ),
        );

        if ( $existing ) {
            return false !== $wpdb->update(
                $group_items_table,
                $payload,
                array( 'id' => (int) $existing ),
                array( '%d', '%d', '%d', '%s', '%s', '%d', '%s' ),
                array( '%d' )
            );
        }

        $payload['created_at'] = current_time( 'mysql' );
        return false !== $wpdb->insert(
            $group_items_table,
            $payload,
            array( '%d', '%d', '%d', '%s', '%s', '%d', '%s', '%s' )
        );
    }

    /**
     * Fetch shared uploads saved against a grouped supplier proposal workspace.
     *
     * @param int $proposal_group_id Proposal group ID.
     * @param int $supplier_id       Optional supplier user ID.
     * @return array<int, array<string, mixed>>
     */
    private function get_supplier_proposal_group_uploads( $proposal_group_id, $supplier_id = 0 ) {
        global $wpdb;

        $this->ensure_supplier_proposal_workspace_support();

        $proposal_group_id = absint( $proposal_group_id );
        $supplier_id       = absint( $supplier_id );

        if ( ! $proposal_group_id ) {
            return array();
        }

        $group_uploads_table = $wpdb->prefix . 'n88_supplier_proposal_group_uploads';
        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$group_uploads_table}'" ) !== $group_uploads_table ) {
            return array();
        }

        if ( $supplier_id ) {
            $rows = $wpdb->get_results(
                $wpdb->prepare(
                    "SELECT id, attachment_id, file_url, file_name, created_at
                    FROM {$group_uploads_table}
                    WHERE proposal_group_id = %d
                    AND supplier_id = %d
                    ORDER BY created_at ASC, id ASC",
                    $proposal_group_id,
                    $supplier_id
                ),
                ARRAY_A
            );
        } else {
            $rows = $wpdb->get_results(
                $wpdb->prepare(
                    "SELECT id, attachment_id, file_url, file_name, created_at
                    FROM {$group_uploads_table}
                    WHERE proposal_group_id = %d
                    ORDER BY created_at ASC, id ASC",
                    $proposal_group_id
                ),
                ARRAY_A
            );
        }

        $uploads = array();
        foreach ( (array) $rows as $row ) {
            $uploads[] = array(
                'id'            => isset( $row['id'] ) ? (int) $row['id'] : 0,
                'attachment_id' => ! empty( $row['attachment_id'] ) ? (int) $row['attachment_id'] : null,
                'file_url'      => ! empty( $row['file_url'] ) ? esc_url_raw( $row['file_url'] ) : '',
                'file_name'     => ! empty( $row['file_name'] ) ? sanitize_file_name( $row['file_name'] ) : 'Attachment',
                'created_at'    => ! empty( $row['created_at'] ) ? $row['created_at'] : null,
            );
        }

        return $uploads;
    }

    /**
     * Commit 3.C.18: Return grouped proposal workspace interpretation data for a designer item view.
     *
     * This exposes supplier quote/skip decisions even when an item has no submitted bid,
     * allowing the designer comparison layer to render explicit "Not Quoted" states and
     * preserve grouped item alignment.
     *
     * @param int $item_id Item ID.
     * @return array<int, array<string, mixed>>
     */
    private function get_item_proposal_group_workspace_states( $item_id ) {
        global $wpdb;

        $this->ensure_supplier_proposal_workspace_support();

        $item_id            = absint( $item_id );
        $groups_table       = $wpdb->prefix . 'n88_supplier_proposal_groups';
        $group_items_table  = $wpdb->prefix . 'n88_supplier_proposal_group_items';
        $users_table        = $wpdb->users;
        $wireframe_supplier = $this->get_default_wireframe_supplier_id();

        if ( ! $item_id ) {
            return array();
        }

        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$groups_table}'" ) !== $groups_table ) {
            return array();
        }

        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$group_items_table}'" ) !== $group_items_table ) {
            return array();
        }

        $rows = $wpdb->get_results(
            $wpdb->prepare(
                "SELECT gi.proposal_group_id, gi.quote_decision, gi.item_state, gi.linked_bid_id, gi.updated_at AS state_updated_at,
                        g.supplier_id, g.workspace_label, g.rfq_reference, g.status AS workspace_status, g.created_at AS workspace_created_at, g.updated_at AS workspace_updated_at,
                        u.display_name AS supplier_name
                FROM {$group_items_table} gi
                INNER JOIN {$groups_table} g ON g.proposal_group_id = gi.proposal_group_id
                LEFT JOIN {$users_table} u ON u.ID = g.supplier_id
                WHERE gi.item_id = %d
                ORDER BY CASE WHEN g.supplier_id = %d THEN 0 ELSE 1 END, g.created_at ASC, g.proposal_group_id ASC",
                $item_id,
                $wireframe_supplier
            ),
            ARRAY_A
        );

        if ( empty( $rows ) ) {
            return array();
        }

        $group_ids = array_values(
            array_unique(
                array_filter(
                    array_map(
                        'absint',
                        wp_list_pluck( (array) $rows, 'proposal_group_id' )
                    )
                )
            )
        );

        $group_items_map = array();
        if ( ! empty( $group_ids ) ) {
            $placeholders = implode( ',', array_fill( 0, count( $group_ids ), '%d' ) );
            $group_rows   = $wpdb->get_results(
                $wpdb->prepare(
                    "SELECT proposal_group_id, item_id, quote_decision, item_state, linked_bid_id
                    FROM {$group_items_table}
                    WHERE proposal_group_id IN ({$placeholders})
                    ORDER BY proposal_group_id ASC, item_id ASC",
                    ...$group_ids
                ),
                ARRAY_A
            );

            foreach ( (array) $group_rows as $group_row ) {
                $proposal_group_id = isset( $group_row['proposal_group_id'] ) ? absint( $group_row['proposal_group_id'] ) : 0;
                $group_item_id     = isset( $group_row['item_id'] ) ? absint( $group_row['item_id'] ) : 0;

                if ( ! $proposal_group_id || ! $group_item_id ) {
                    continue;
                }

                if ( ! isset( $group_items_map[ $proposal_group_id ] ) ) {
                    $group_items_map[ $proposal_group_id ] = array(
                        'item_ids'    => array(),
                        'item_states' => array(),
                    );
                }

                $group_items_map[ $proposal_group_id ]['item_ids'][] = $group_item_id;
                $group_items_map[ $proposal_group_id ]['item_states'][ $group_item_id ] = array(
                    'quote_decision' => ! empty( $group_row['quote_decision'] ) ? sanitize_text_field( $group_row['quote_decision'] ) : 'quote',
                    'item_state'     => ! empty( $group_row['item_state'] ) ? sanitize_text_field( $group_row['item_state'] ) : 'not_ready',
                    'linked_bid_id'  => ! empty( $group_row['linked_bid_id'] ) ? absint( $group_row['linked_bid_id'] ) : null,
                );
            }
        }

        $workspaces = array();
        foreach ( (array) $rows as $row ) {
            $proposal_group_id = isset( $row['proposal_group_id'] ) ? absint( $row['proposal_group_id'] ) : 0;
            $supplier_id       = isset( $row['supplier_id'] ) ? absint( $row['supplier_id'] ) : 0;
            if ( ! $proposal_group_id || ! $supplier_id ) {
                continue;
            }

            $group_items = isset( $group_items_map[ $proposal_group_id ] ) ? $group_items_map[ $proposal_group_id ] : array(
                'item_ids'    => array(),
                'item_states' => array(),
            );

            $item_ids = array_values(
                array_unique(
                    array_map( 'absint', (array) $group_items['item_ids'] )
                )
            );
            sort( $item_ids );

            $workspaces[] = array(
                'proposal_group_id'     => $proposal_group_id,
                'supplier_id'           => $supplier_id,
                'supplier_name'         => ! empty( $row['supplier_name'] ) ? sanitize_text_field( $row['supplier_name'] ) : 'Supplier #' . $supplier_id,
                'supplier_is_wireframe' => $wireframe_supplier > 0 && $supplier_id === $wireframe_supplier,
                'quote_decision'        => ! empty( $row['quote_decision'] ) ? sanitize_text_field( $row['quote_decision'] ) : 'quote',
                'item_state'            => ! empty( $row['item_state'] ) ? sanitize_text_field( $row['item_state'] ) : 'not_ready',
                'linked_bid_id'         => ! empty( $row['linked_bid_id'] ) ? absint( $row['linked_bid_id'] ) : null,
                'workspace_label'       => ! empty( $row['workspace_label'] ) ? sanitize_text_field( $row['workspace_label'] ) : '',
                'rfq_reference'         => ! empty( $row['rfq_reference'] ) ? sanitize_text_field( $row['rfq_reference'] ) : '',
                'workspace_status'      => ! empty( $row['workspace_status'] ) ? sanitize_text_field( $row['workspace_status'] ) : '',
                'workspace_created_at'  => ! empty( $row['workspace_created_at'] ) ? $row['workspace_created_at'] : null,
                'workspace_updated_at'  => ! empty( $row['workspace_updated_at'] ) ? $row['workspace_updated_at'] : null,
                'state_updated_at'      => ! empty( $row['state_updated_at'] ) ? $row['state_updated_at'] : null,
                'item_ids'              => $item_ids,
                'item_count'            => count( $item_ids ),
                'item_states'           => isset( $group_items['item_states'] ) && is_array( $group_items['item_states'] ) ? $group_items['item_states'] : array(),
                'shared_uploads'        => $this->get_supplier_proposal_group_uploads( $proposal_group_id, $supplier_id ),
            );
        }

        return $workspaces;
    }

    /**
     * Create custom roles with appropriate capabilities (Commit 2.2.1)
     */
    public function create_custom_roles() {
        // Create n88_designer role
        if ( ! get_role( 'n88_designer' ) ) {
        add_role(
                'n88_designer',
            __( 'Creator', 'n88-rfq' ),
            array(
                'read' => true,
                'upload_files' => true,
                    // Legacy capabilities for backward compatibility
                'n88_access_boards' => true,
                'n88_access_items' => true,
                'n88_access_projects' => true,
            )
        );
        }

        // Create n88_supplier_admin role
        if ( ! get_role( 'n88_supplier_admin' ) ) {
            add_role(
                'n88_supplier_admin',
                __( 'Maker', 'n88-rfq' ),
                array(
                    'read' => true,
                    'n88_view_supplier_queue' => true,
                )
            );
        }

        // Create n88_system_operator role
        if ( ! get_role( 'n88_system_operator' ) ) {
            add_role(
                'n88_system_operator',
                __( 'System Operator', 'n88-rfq' ),
                array(
                    'read' => true,
                    'n88_view_supplier_queue' => true,
                    'n88_view_global_queue' => true,
                    'manage_options' => true, // Full admin access
                )
            );
        }

        // Migrate existing 'designer' role to 'n88_designer' if it exists
        $old_designer_role = get_role( 'designer' );
        if ( $old_designer_role ) {
            // Get all users with old designer role
            $users = get_users( array( 'role' => 'designer' ) );
            foreach ( $users as $user ) {
                $user_obj = new WP_User( $user->ID );
                $user_obj->remove_role( 'designer' );
                $user_obj->add_role( 'n88_designer' );
            }
            // Remove old role (optional - keeping for backward compatibility during migration)
            // remove_role( 'designer' );
        }
    }

    /**
     * Enqueue authentication styles
     */
    public function enqueue_auth_styles() {
        if ( defined( 'N88_RFQ_PLUGIN_URL' ) ) {
            $plugin_url = trailingslashit( N88_RFQ_PLUGIN_URL );
        } else {
            $plugin_file = dirname( dirname( __FILE__ ) ) . '/n88-rfq-platform.php';
            $plugin_url = trailingslashit( plugin_dir_url( $plugin_file ) );
        }

        wp_enqueue_style(
            'n88-ibm-plex-mono',
            'https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@400;500;600;700&display=swap',
            array(),
            null
        );
        $css_file = ( defined( 'N88_RFQ_PLUGIN_DIR' ) ? N88_RFQ_PLUGIN_DIR : dirname( dirname( __FILE__ ) ) . '/' ) . 'assets/css/n88-rfq-auth.css';
        $css_ver = file_exists( $css_file ) ? filemtime( $css_file ) : N88_RFQ_VERSION;
        wp_enqueue_style(
            'n88-rfq-auth',
            $plugin_url . 'assets/css/n88-rfq-auth.css',
            array( 'n88-ibm-plex-mono' ),
            $css_ver
        );
        $sq_css = ( defined( 'N88_RFQ_PLUGIN_DIR' ) ? N88_RFQ_PLUGIN_DIR : dirname( dirname( __FILE__ ) ) . '/' ) . 'assets/css/n88-supplier-queue.css';
        $sq_ver = file_exists( $sq_css ) ? filemtime( $sq_css ) : N88_RFQ_VERSION;
        wp_enqueue_style( 'n88-supplier-queue', $plugin_url . 'assets/css/n88-supplier-queue.css', array( 'n88-rfq-auth' ), $sq_ver );
    }

