            window.n88SupplierModalSwitchTab = function(tabName) {
                if (tabName === 'bid') tabName = 'overview';
                var tabs = ['overview', 'workflow'];
                var tabStyle = 'flex: 1; padding: 12px 16px; background: #000; border: none; border-bottom: 2px solid transparent; color: #888; font-size: 12px; font-weight: 400; cursor: pointer; font-family: monospace;';
                var tabActiveStyle = 'flex: 1; padding: 12px 16px; background: #111111; border: none; border-bottom: 2px solid #FF0065; color: #FF0065; font-size: 12px; font-weight: 600; cursor: pointer; font-family: monospace;';
                var wrap = document.getElementById('n88-supplier-workflow-timeline-wrap');
                var itemId = wrap ? wrap.getAttribute('data-item-id') : '';
                var workflowThreadBox = itemId ? document.getElementById('n88-supplier-workflow-thread-box-' + itemId) : null;
                tabs.forEach(function(name) {
                    var btn = document.getElementById('n88-supplier-tab-' + name);
                    var panel = document.getElementById('n88-supplier-panel-' + name);
                    if (btn) { btn.style.cssText = name === tabName ? tabActiveStyle : tabStyle; }
                    if (panel) {
                        if (name === tabName) {
                            panel.style.display = 'flex';
                            panel.style.flexDirection = 'column';
                            if (name === 'workflow' && typeof window.n88LoadSupplierWorkflowTimeline === 'function') {
                                window.n88LoadSupplierWorkflowTimeline();
                                if (workflowThreadBox) workflowThreadBox.style.display = 'flex';
                                if (itemId && typeof loadSupplierMessagesInline === 'function') {
                                    var workflowContext = getSupplierWorkflowMessageContextType(itemId);
                                    updateSupplierWorkflowThreadHeading(itemId, workflowContext);
                                    loadSupplierMessagesInline(itemId, workflowContext);
                                }
                            }
                            if (name === 'prototype' && typeof window.initPrototypeVideoForms === 'function') {
                                window.initPrototypeVideoForms();
                            }
                        } else {
                            panel.style.display = 'none';
                        }
                    }
                });
                if (workflowThreadBox && tabName !== 'workflow') workflowThreadBox.style.display = 'none';
            };

            window.n88SupplierWorkflowShowStep = function(idx) {
                var wrap = document.getElementById('n88-supplier-workflow-timeline-wrap');
                if (!wrap) return;
                wrap.setAttribute('data-active-step', String(idx));
                var details = wrap.querySelectorAll('.n88-workflow-step-detail');
                for (var i = 0; i < details.length; i++) {
                    var stepId = details[i].getAttribute('id') || '';
                    var stepNum = parseInt(stepId.replace('n88-supplier-workflow-step-', ''), 10);
                    details[i].style.display = (stepNum === idx) ? 'block' : 'none';
                }
                var row = document.getElementById('n88-supplier-workflow-step-row');
                if (row) {
                    row.setAttribute('data-active-idx', String(idx));
                    var green = '#FF0065';
                    var darkBorder = '#555';
                    var stepLabels = ['Proposal Submitted', 'Design Evaluation', 'Award Decision', 'Production', 'Quality Review & Packing', 'Delivery'];
                    var steps = row.querySelectorAll('[data-step-idx]');
                    for (var s = 0; s < steps.length; s++) {
                        var si = parseInt(steps[s].getAttribute('data-step-idx'), 10);
                        var isActive = idx === si;
                        var circleBg = isActive ? green : '#333';
                        var circleBorder = isActive ? green : darkBorder;
                        var circleColor = isActive ? '#0a0a0a' : '#888';
                        var labelColor = isActive ? green : '#888';
                        var circle = steps[s].querySelector('div[style*="border-radius: 50%"]');
                        var label = steps[s].querySelector('div[style*="font-size: 10px"]');
                        if (circle) { circle.style.background = circleBg; circle.style.borderColor = circleBorder; circle.style.color = circleColor; }
                        if (label) label.style.color = labelColor;
                    }
                }
                var itemId = wrap.getAttribute('data-item-id');
                if (itemId && typeof loadSupplierMessagesInline === 'function') {
                    var workflowContext = getSupplierWorkflowMessageContextType(itemId);
                    updateSupplierWorkflowThreadHeading(itemId, workflowContext);
                    loadSupplierMessagesInline(itemId, workflowContext);
                }
                if (typeof window.initPrototypeVideoForms === 'function') window.initPrototypeVideoForms();
            };

            window.n88LoadSupplierWorkflowTimeline = function() {
                var wrap = document.getElementById('n88-supplier-workflow-timeline-wrap');
                var container = document.getElementById('n88-supplier-workflow-timeline');
                if (!wrap || !container) return;
                if (wrap.getAttribute('data-timeline-loaded') === '1') return;
                var itemId = wrap.getAttribute('data-item-id');
                if (!itemId) return;
                var nonce = '<?php echo esc_js( wp_create_nonce( 'n88_get_item_rfq_state' ) ); ?>';
                if (!nonce) return;
                // Preserve Steps 1-3: only show loading in Steps 4-6, never wipe the container
                // IMPORTANT: Do NOT overwrite Step 4 if it already has the Official Quote PDF form (supplier awarded  must submit PDF)
                var step4El = document.getElementById('n88-supplier-workflow-step-3');
                var step5El = document.getElementById('n88-supplier-workflow-step-4');
                var step6El = document.getElementById('n88-supplier-workflow-step-5');
                var hasOriginalStructure = !!(step4El && step5El && step6El);
                var step4HasOfficialQuote = step4El && (step4El.innerHTML.indexOf('official_quote_pdf') !== -1 || step4El.innerHTML.indexOf('Submit Official Quote PDF') !== -1 || step4El.innerHTML.indexOf('Quote file submitted') !== -1);
                if (hasOriginalStructure) {
                    var loadingHtml = '<div style="padding: 12px; color: #888; font-size: 12px;">Loading timelineâ€¦</div>';
                    if (!step4HasOfficialQuote) step4El.innerHTML = loadingHtml;
                    step5El.innerHTML = loadingHtml;
                    step6El.innerHTML = loadingHtml;
                } else {
                    container.innerHTML = '<div style="padding: 12px; color: #888; font-size: 12px;">Loading timelineâ€¦</div>';
                }
                var formData = new FormData();
                formData.append('action', 'n88_get_item_timeline');
                formData.append('item_id', itemId);
                formData.append('_ajax_nonce', nonce);
                fetch('<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>', { method: 'POST', body: formData, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        var step4ElPost = document.getElementById('n88-supplier-workflow-step-3');
                        var step5ElPost = document.getElementById('n88-supplier-workflow-step-4');
                        var step6ElPost = document.getElementById('n88-supplier-workflow-step-5');
                        var hasOriginalPost = !!(step4ElPost && step5ElPost && step6ElPost);
                        var errHtml = '<div style="padding: 12px; color: #cc6666; font-size: 12px;">' + (data.message || 'Failed to load timeline.') + '</div>';
                        var errHtml2 = '<div style="padding: 12px; color: #888;">Timeline data incomplete.</div>';
                        if (!data.success || !data.data || !data.data.timeline) {
                            if (hasOriginalPost) {
                                if (step4ElPost) step4ElPost.innerHTML = errHtml;
                                if (step5ElPost) step5ElPost.innerHTML = errHtml;
                                if (step6ElPost) step6ElPost.innerHTML = errHtml;
                            } else {
                                container.innerHTML = errHtml;
                            }
                            return;
                        }
                        var t = data.data.timeline;
                        var steps = t.steps || [];
                        if (steps.length < 6) {
                            if (hasOriginalPost) {
                                if (step4ElPost) step4ElPost.innerHTML = errHtml2;
                                if (step5ElPost) step5ElPost.innerHTML = errHtml2;
                                if (step6ElPost) step6ElPost.innerHTML = errHtml2;
                            } else {
                                container.innerHTML = errHtml2;
                            }
                            wrap.setAttribute('data-timeline-loaded', '1');
                            return;
                        }
                        var green = '#FF0065';
                        var darkText = '#ccc';
                        var darkBorder = '#555';
                        var selectedIdx = 0;
                        var savedActiveIdx = parseInt(wrap.getAttribute('data-active-step') || '', 10);
                        if (!isNaN(savedActiveIdx) && savedActiveIdx >= 0 && savedActiveIdx < steps.length) {
                            selectedIdx = savedActiveIdx;
                        }
                        var supplierEvidenceByStep = data.data.supplier_step_evidence_by_step || {};
                        var step456Videos = data.data.step_456_videos || {};
                        var validationState = data.data.validation_state || t.validation_state || {};
                        if (isNaN(savedActiveIdx) && validationState && validationState.request && validationState.request.requested_at && (!validationState.supplier || !validationState.supplier.updated_at)) {
                            selectedIdx = 1;
                        }
                        function escHtml(value) {
