                    // Comparison Points: use comparison_points; support legacy comparisons; prefer .n88-smart-alt-checkbox
                    var compsEmb = sa.comparison_points || sa.comparisons || [];
                    if (compsEmb.length > 0) {
                        compsEmb.forEach(function(comp) {
