            // Attach event listeners
            document.addEventListener('DOMContentLoaded', function() {
                document.querySelectorAll('.n88-open-bid-modal').forEach(function(button) {
                    button.addEventListener('click', function(e) {
                        var itemId = this.getAttribute('data-item-id');
                        var actionBadge = this.getAttribute('data-action-badge');
                        
                        // M6: Block if expired
                        if (actionBadge === 'expired') {
                            e.preventDefault();
                            e.stopPropagation();
                            alert('This RFQ is no longer accepting bids.');
                            return false;
                        }
                        
                        openBidModal(itemId);
                    });
                });

                document.querySelectorAll('.n88-supplier-batch-item-checkbox').forEach(function(checkbox) {
                    checkbox.addEventListener('change', function() {
                        var itemId = this.getAttribute('data-item-id');
                        if (this.checked) {
                            window.n88SupplierBatchState.selectedItems[itemId] = {
                                item_id: itemId,
                                title: this.getAttribute('data-item-title') || ('Item #' + itemId),
                                category: this.getAttribute('data-category') || ''
                            };
                        } else {
                            delete window.n88SupplierBatchState.selectedItems[itemId];
                        }
                        refreshBatchSelectionUI();
                    });
                });

                var selectAllBatch = document.getElementById('n88-supplier-select-all-batch');
                if (selectAllBatch) {
                    selectAllBatch.addEventListener('change', function() {
                        var checked = !!this.checked;
                        document.querySelectorAll('.n88-supplier-batch-item-checkbox').forEach(function(checkbox) {
                            checkbox.checked = checked;
                            var itemId = checkbox.getAttribute('data-item-id');
                            if (checked) {
                                window.n88SupplierBatchState.selectedItems[itemId] = {
                                    item_id: itemId,
                                    title: checkbox.getAttribute('data-item-title') || ('Item #' + itemId),
                                    category: checkbox.getAttribute('data-category') || ''
                                };
                            } else {
                                delete window.n88SupplierBatchState.selectedItems[itemId];
                            }
                        });
                        refreshBatchSelectionUI();
                    });
                }

                var openBatchBtn = document.getElementById('n88-open-batch-proposal-modal');
                if (openBatchBtn) {
                    openBatchBtn.addEventListener('click', function() {
                        openBatchProposalModal();
                    });
                }
                 
                // Close modal on backdrop click (edge panels or wrapper)
                var modal = document.getElementById('n88-supplier-bid-modal');
                if (modal) {
                    modal.addEventListener('click', function(e) {
                        if (e.target === modal || e.target.closest('.n88-supplier-modal-edge') || e.target.classList.contains('n88-supplier-modal-edge')) {
                            closeBidModal();
                        }
                    });
                }
                
                // Close bid form modal on backdrop click
                var bidFormModal = document.getElementById('n88-supplier-bid-form-modal');
                if (bidFormModal) {
                    bidFormModal.addEventListener('click', function(e) {
                        if (e.target === bidFormModal) {
                            closeBidFormModal();
                        }
                    });
                }

                var batchModal = document.getElementById('n88-supplier-batch-proposal-modal');
                if (batchModal) {
                    batchModal.addEventListener('click', function(e) {
                        if (e.target === batchModal) {
                            closeBatchProposalModal();
                        }
                    });
                }

                document.addEventListener('click', function(e) {
                    var accordionBtn = e.target && e.target.closest ? e.target.closest('.n88-batch-accordion-toggle') : null;
                    if (accordionBtn) {
                        toggleBatchProposalAccordion(accordionBtn.getAttribute('data-item-id'));
                        return;
                    }
                    var closeBtn = e.target && e.target.closest ? e.target.closest('#n88-close-batch-proposal-modal') : null;
                    if (closeBtn) {
                        closeBatchProposalModal();
                        return;
                    }
                    var saveAllBtn = e.target && e.target.closest ? e.target.closest('#n88-batch-save-all-btn') : null;
                    if (saveAllBtn) {
                        runBatchProposalAction('save');
                        return;
                    }
                    var submitAllBtn = e.target && e.target.closest ? e.target.closest('#n88-batch-submit-all-btn') : null;
                    if (submitAllBtn) {
                        runBatchProposalAction('submit');
                    }
                });

                document.addEventListener('change', function(e) {
                    var quoteChoice = e.target && e.target.matches ? e.target.matches('input[name^="n88_batch_quote_choice_"]') : false;
                    if (!quoteChoice) {
                        return;
                    }
                    var name = e.target.getAttribute('name') || '';
                    var itemId = name.replace('n88_batch_quote_choice_', '');
                    var skipNote = document.getElementById('n88-batch-skip-note-' + itemId);
                    var formHost = document.getElementById('n88-batch-form-host-' + itemId);
                    if (e.target.value === 'skip') {
                        if (skipNote) {
                            skipNote.style.display = 'block';
                        }
                        if (formHost) {
                            formHost.style.opacity = '0.45';
                            formHost.style.pointerEvents = 'none';
                        }
                        setBatchItemState(itemId, 'not_quoted');
                        persistBatchItemState(itemId, 'skip', 'not_quoted', null);
                    } else {
                        if (skipNote) {
                            skipNote.style.display = 'none';
                        }
                        if (formHost) {
                            formHost.style.opacity = '1';
                            formHost.style.pointerEvents = 'auto';
                        }
                        persistBatchItemState(itemId, 'quote', detectBatchItemState(itemId), (window.n88SupplierBatchState.itemData[itemId] || {}).bid_id || null);
                        refreshSingleBatchItemState(itemId);
                    }
                });

                document.addEventListener('click', function(e) {
                    var uploadBtn = e.target && e.target.closest ? e.target.closest('#n88-batch-shared-upload-btn') : null;
                    if (!uploadBtn) {
                        return;
                    }
                    var workspace = window.n88SupplierBatchState.workspace || {};
                    var fileInput = document.getElementById('n88-batch-shared-files');
                    if (!workspace.proposal_group_id) {
                        alert('Batch workspace is not ready yet.');
                        return;
                    }
                    if (!fileInput || !fileInput.files || !fileInput.files.length) {
                        alert('Select shared files first.');
                        return;
                    }
                    var formData = new FormData();
                    formData.append('action', 'n88_upload_supplier_batch_shared_assets');
                    formData.append('proposal_group_id', workspace.proposal_group_id);
                    Array.prototype.forEach.call(fileInput.files, function(file) {
                        formData.append('shared_attachments[]', file);
                    });
                    formData.append('_ajax_nonce', '<?php echo wp_create_nonce( 'n88_upload_supplier_batch_shared_assets' ); ?>');
                    uploadBtn.disabled = true;
                    uploadBtn.textContent = '[ Uploading... ]';
                    fetch('<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>', {
                        method: 'POST',
                        body: formData,
                        credentials: 'same-origin'
                    }).then(function(response) {
                        return response.json();
                    }).then(function(result) {
                        if (!result.success || !result.data) {
                            throw new Error((result.data && result.data.message) || 'Shared upload failed.');
                        }
                        window.n88SupplierBatchState.sharedUploads = (window.n88SupplierBatchState.sharedUploads || []).concat(result.data.uploads || []);
                        refreshBatchSharedUploads();
                        fileInput.value = '';
                    }).catch(function(error) {
                        alert(error.message || 'Shared upload failed.');
                    }).finally(function() {
                        uploadBtn.disabled = false;
                        uploadBtn.textContent = '[ Upload Shared Files ]';
                    });
                });

                document.addEventListener('input', function(e) {
                    var panel = e.target && e.target.closest ? e.target.closest('.n88-batch-item-panel') : null;
                    if (panel) {
                        refreshSingleBatchItemState(panel.getAttribute('data-item-id'));
                    }
                });

                refreshBatchSelectionUI();
            });
             
            // Expose to global scope
            window.openBidModal = openBidModal;
            window.closeBidModal = closeBidModal;
            window.openBatchProposalModal = openBatchProposalModal;
            window.closeBatchProposalModal = closeBatchProposalModal;
            window.n88BatchProposalRefreshItemState = refreshSingleBatchItemState;
            window.submitOfficialQuotePDF = function(form, itemId, bidId) {
                try {
                    if (!bidId) {
                        alert('Unable to determine awarded bid for this item.');
                        return false;
                    }
                    var fileInput = form.querySelector('input[type="file"][name="official_quote_pdf"]');
                    if (!fileInput || !fileInput.files || !fileInput.files.length) {
                        alert('Please choose a PDF file to upload.');
                        return false;
                    }
                    var submitBtn = form.querySelector('button[type="submit"]');
                    if (submitBtn) {
                        submitBtn.disabled = true;
                        submitBtn.textContent = 'Submittingâ€¦';
                    }
                    var fd = new FormData(form);
                    fd.append('action', 'n88_submit_official_quote_pdf');
                    fd.append('item_id', String(itemId));
                    fd.append('bid_id', String(bidId));
                    fetch('<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>', {
                        method: 'POST',
                        body: fd
                    }).then(function(r) { return r.json(); }).then(function(data) {
                        if (submitBtn) {
                            submitBtn.disabled = false;
                            submitBtn.textContent = '[ Submit Official Quote PDF ]';
                        }
                        if (data.success) {
                            alert(data.data && data.data.message ? data.data.message : 'Official Quote PDF submitted successfully.');
                            if (typeof openBidModal === 'function') {
                                var modal = document.getElementById('n88-supplier-bid-modal');
                                if (modal) {
                                    modal.style.display = 'none';
                                    setTimeout(function() { openBidModal(itemId, 'workflow'); }, 300);
                                } else {
                                    window.location.reload();
                                }
                            } else {
                                window.location.reload();
                            }
                        } else {
                            alert((data.data && data.data.message) || data.message || 'Failed to submit Official Quote PDF.');
                        }
                    }).catch(function(err) {
                        console.error('Error submitting official quote PDF:', err);
                        if (submitBtn) {
                            submitBtn.disabled = false;
                            submitBtn.textContent = '[ Submit Official Quote PDF ]';
                        }
                        alert('Error submitting Official Quote PDF. Please try again.');
                    });
                } catch (e) {
                    console.error('Error in submitOfficialQuotePDF:', e);
                    alert('Error submitting Official Quote PDF. Please try again.');
                }
                return false;
            };
            // Withdraw bid function (Commit 2.3.5)
            function withdrawBid(itemId) {
                if (!confirm('Are you sure you want to withdraw your bid? You will be able to resubmit a new bid after withdrawal.')) {
                    return;
                }
                
                var formData = new FormData();
                formData.append('action', 'n88_withdraw_supplier_bid');
                formData.append('item_id', itemId);
                formData.append('_ajax_nonce', '<?php echo wp_create_nonce( 'n88_withdraw_supplier_bid' ); ?>');
                
                var ajaxUrl = typeof ajaxurl !== 'undefined' ? ajaxurl : '<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>';
                fetch(ajaxUrl, {
                    method: 'POST',
                    body: formData
                })
                .then(function(response) { return response.json(); })
                .then(function(data) {
                    if (data.success) {
                        alert(data.data.message || 'Bid withdrawn successfully.');
                        // Close the modal and reload the page so the supplier sees the updated state on the board
                        closeBidModal();
                        setTimeout(function() {
                            window.location.reload();
                        }, 150);
                    } else {
                        alert(data.data.message || 'Failed to withdraw bid. Please try again.');
                    }
                })
                .catch(function(error) {
                    console.error('Error withdrawing bid:', error);
                    alert('An error occurred while withdrawing the bid. Please try again.');
                });
            }
            
            window.openBidFormModal = openBidFormModal;
            window.closeBidFormModal = closeBidFormModal;
            window.addVideoLink = addVideoLink;
            window.removeVideoLink = removeVideoLink;
            window.validateVideoLink = validateVideoLink;
            window.validateBidForm = validateBidForm;
            window.withdrawBid = withdrawBid;
            window.validateAndSubmitBid = validateAndSubmitBid;
            window.openSupplierImageLightbox = openSupplierImageLightbox;
            window.closeSupplierImageLightbox = closeSupplierImageLightbox;
            window.handleBidPhotosChange = handleBidPhotosChange;
            window.removeBidPhoto = removeBidPhoto;
            window.removeBidPhotoEmbedded = removeBidPhotoEmbedded;
        })();
        </script>
        <?php
        return ob_get_clean();
    }

