    /**
     * Get country name by code
     */
    private function get_country_name( $code ) {
        $countries = $this->get_countries_list();
        return isset( $countries[ $code ] ) ? $countries[ $code ] : $code;
    }

    /**
     * Commit 2.3.8: Map country code to origin_region for duty calculation
     * 
     * @param string $country_code 2-letter country code (e.g., 'US', 'CN', 'IN')
     * @return string|null Origin region: 'USA', 'CANADA', 'ASIA', 'EUROPE', 'MIDDLE_EAST', 'OTHER', or null
     */
    private function map_country_to_origin_region( $country_code ) {
        if ( empty( $country_code ) ) {
            return null;
        }
        
        $country_code = strtoupper( trim( $country_code ) );
        
        // USA
        if ( $country_code === 'US' ) {
            return 'USA';
        }
        
        // Canada
        if ( $country_code === 'CA' ) {
            return 'CANADA';
        }
        
        // Asia countries
        $asia_countries = array(
            'CN', // China
            'IN', // India
            'JP', // Japan
            'KR', // South Korea
            'SG', // Singapore
            'MY', // Malaysia
            'TH', // Thailand
            'ID', // Indonesia
            'PH', // Philippines
            'VN', // Vietnam
            'TW', // Taiwan
            'HK', // Hong Kong
            'BD', // Bangladesh
            'PK', // Pakistan
            'LK', // Sri Lanka
            'MM', // Myanmar
            'KH', // Cambodia
            'LA', // Laos
            'MN', // Mongolia
            'NP', // Nepal
        );
        if ( in_array( $country_code, $asia_countries, true ) ) {
            return 'ASIA';
        }
        
        // Europe countries
        $europe_countries = array(
            'GB', // United Kingdom
            'DE', // Germany
            'FR', // France
            'IT', // Italy
            'ES', // Spain
            'NL', // Netherlands
            'BE', // Belgium
            'CH', // Switzerland
            'AT', // Austria
            'SE', // Sweden
            'NO', // Norway
            'DK', // Denmark
            'FI', // Finland
            'PL', // Poland
            'CZ', // Czech Republic
            'IE', // Ireland
            'PT', // Portugal
            'GR', // Greece
            'RO', // Romania
            'HU', // Hungary
            'BG', // Bulgaria
            'HR', // Croatia
            'SK', // Slovakia
            'SI', // Slovenia
            'LT', // Lithuania
            'LV', // Latvia
            'EE', // Estonia
        );
        if ( in_array( $country_code, $europe_countries, true ) ) {
            return 'EUROPE';
        }
        
        // Middle East countries
        $middle_east_countries = array(
            'AE', // United Arab Emirates
            'SA', // Saudi Arabia
            'IL', // Israel
            'TR', // Turkey
            'IQ', // Iraq
            'IR', // Iran
            'JO', // Jordan
            'LB', // Lebanon
            'KW', // Kuwait
            'OM', // Oman
            'QA', // Qatar
            'BH', // Bahrain
            'YE', // Yemen
        );
        if ( in_array( $country_code, $middle_east_countries, true ) ) {
            return 'MIDDLE_EAST';
        }
        
        // Default to OTHER for all other countries
        return 'OTHER';
    }

