        nocache_headers();

        // Get site name
        $site_name = get_bloginfo( 'name' );
        $home_url = home_url( '/' );

        ?>
        <!DOCTYPE html>
        <html <?php language_attributes(); ?>>
        <head>
            <meta charset="<?php bloginfo( 'charset' ); ?>">
            <meta name="viewport" content="width=device-width, initial-scale=1.0">
            <title><?php echo esc_html( $title ); ?> - <?php echo esc_html( $site_name ); ?></title>
            <style>
                * {
                    margin: 0;
                    padding: 0;
                    box-sizing: border-box;
                }
                body {
                    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen-Sans, Ubuntu, Cantarell, "Helvetica Neue", sans-serif;
                    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
                    min-height: 100vh;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    padding: 20px;
                }
                .error-container {
                    background: #ffffff;
                    border-radius: 12px;
                    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);
                    max-width: 500px;
                    width: 100%;
                    padding: 50px 40px;
                    text-align: center;
                }
                .error-code {
                    font-size: 72px;
                    font-weight: bold;
                    color: #e74c3c;
                    line-height: 1;
                    margin-bottom: 20px;
                }
                .error-title {
                    font-size: 28px;
                    font-weight: 600;
                    color: #2c3e50;
                    margin-bottom: 15px;
                }
                .error-message {
                    font-size: 16px;
                    color: #7f8c8d;
                    line-height: 1.6;
                    margin-bottom: 30px;
                }
                .error-actions {
                    margin-top: 30px;
                }
                .btn {
                    display: inline-block;
                    padding: 12px 30px;
                    background: #667eea;
                    color: #ffffff;
                    text-decoration: none;
                    border-radius: 6px;
                    font-weight: 500;
                    transition: background 0.3s ease;
                }
                .btn:hover {
                    background: #5568d3;
                }
                .btn-secondary {
                    background: #95a5a6;
                    margin-left: 10px;
                }
                .btn-secondary:hover {
                    background: #7f8c8d;
                }
            </style>
        </head>
        <body>
            <div class="error-container">
                <div class="error-code">403</div>
                <h1 class="error-title"><?php echo esc_html( $title ); ?></h1>
                <p class="error-message"><?php echo esc_html( $message ); ?></p>
                <div class="error-actions">
                    <a href="<?php echo esc_url( $home_url ); ?>" class="btn">Go to Homepage</a>
                    <?php if ( is_user_logged_in() ) : ?>
                        <?php
                        $current_user = wp_get_current_user();
                        $redirect_url = self::get_role_redirect_url_static( $current_user );
                        if ( $redirect_url ) :
                        ?>
                            <a href="<?php echo esc_url( $redirect_url ); ?>" class="btn btn-secondary">Go to Dashboard</a>
                        <?php endif; ?>
                    <?php endif; ?>
                </div>
            </div>
        </body>
        </html>
        <?php
    }

    /**
     * Render supplier onboarding form (Commit 2.2.7)
     */
    public function render_supplier_onboarding( $atts = array() ) {
        // Allow admins to edit pages even if they don't have supplier role
        if ( is_admin() && current_user_can( 'edit_pages' ) ) {
            return '<p><em>Supplier Onboarding page - This shortcode will display the supplier onboarding form.</em></p>';
        }

        // Check if user is logged in and is a supplier admin
        if ( ! is_user_logged_in() ) {
            wp_redirect( home_url( '/login/' ) );
            exit;
        }

        $current_user = wp_get_current_user();
        $is_supplier = in_array( 'n88_supplier_admin', $current_user->roles, true );
        
        if ( ! $is_supplier ) {
            wp_die( 'Access denied. Maker account required.', 'Access Denied', array( 'response' => 403 ) );
        }

        global $wpdb;
        $this->sync_supplier_onboarding_keyword_library();
        $this->ensure_supplier_media_library_support();
        $categories_table = $wpdb->prefix . 'n88_categories';
        $supplier_profiles_table = $wpdb->prefix . 'n88_supplier_profiles';
        $supplier_keyword_map_table = $wpdb->prefix . 'n88_supplier_keyword_map';
        $onboarding_category_names = array_keys( $this->get_supplier_onboarding_category_keywords() );
        $categories = array();
        foreach ( $onboarding_category_names as $category_name ) {
            $category_row = $wpdb->get_row(
                $wpdb->prepare(
                    "SELECT category_id, name FROM {$categories_table} WHERE LOWER(name) = LOWER(%s) LIMIT 1",
                    $category_name
                )
            );
            if ( $category_row ) {
                $category_row->display_name = $category_name;
                $categories[] = $category_row;
            }
        }

        // Check if profile exists and fetch existing data (Commit 2.2.7)
        $existing_profile = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$supplier_profiles_table} WHERE supplier_id = %d",
            $current_user->ID
        ) );

        // Fetch existing selected keywords
        $existing_keyword_ids = array();
        if ( $existing_profile ) {
            $existing_keyword_ids = $wpdb->get_col( $wpdb->prepare(
                "SELECT keyword_id FROM {$supplier_keyword_map_table} WHERE supplier_id = %d",
                $current_user->ID
            ) );
        }

        $is_edit_mode = ! empty( $existing_profile );
        $form_title = $is_edit_mode ? 'Update Supplier Profile' : 'Maker Onboarding';
        $form_description = $is_edit_mode ? 'Update your profile information.' : 'Complete your profile to enable routing and matching.';

        ob_start();
        ?>
        <div class="n88-supplier-onboarding-wrap">
            <div class="n88-supplier-onboarding-card">
                <div class="n88-auth-logo">
                    <h1 class="n88-auth-logo-title">WireFrame (OS)</h1>
                    <p class="n88-auth-logo-by">By Neev</p>
                </div>
                <h1 class="n88-onboarding-title"><?php echo esc_html( $form_title ); ?></h1>
                <p class="n88-onboarding-subtitle"><?php echo esc_html( $form_description ); ?></p>
            
            <form id="n88-supplier-onboarding-form" class="n88-auth-form">
                <?php wp_nonce_field( 'n88_save_supplier_profile', 'n88_supplier_profile_nonce' ); ?>
                
                <div class="n88-form-group">
                    <label for="n88-primary-category">Primary Category <span class="n88-required-asterisk">*</span></label>
                    <select id="n88-primary-category" name="primary_category_id" required>
                        <option value="">Select a category</option>
                        <?php foreach ( $categories as $category ) : ?>
                            <option value="<?php echo esc_attr( $category->category_id ); ?>" <?php selected( $existing_profile && $existing_profile->primary_category_id == $category->category_id ); ?>>
                                <?php echo esc_html( isset( $category->display_name ) ? $category->display_name : $category->name ); ?>
                            </option>
                        <?php endforeach; ?>
                    </select>
                </div>

                <div class="n88-form-group">
                    <label>Suggested Keywords</label>
                    <p class="n88-field-desc">Select keywords that match your capabilities. Keywords are filtered by your selected category.</p>
                    <div id="n88-keywords-container" class="n88-keywords-container">
                        <p class="n88-keywords-placeholder">Select a category first to see keywords.</p>
                    </div>
                </div>

                <div class="n88-form-group">
                    <label for="n88-freeform-keywords">Additional Keywords</label>
                    <p class="n88-field-desc">Enter any additional keywords that describe your capabilities (one per line). These will be reviewed before approval.<?php echo $is_edit_mode ? ' New keywords will be added to your existing ones.' : ''; ?></p>
                    <textarea id="n88-freeform-keywords" name="freeform_keywords" rows="4" placeholder="Enter keywords, one per line..."></textarea>
                </div>

                <div class="n88-form-group">
                    <label>Capabilities</label>
                    <div style="display: flex; flex-direction: column; gap: 12px;">
                        <label class="n88-capability-item">
                            <input type="checkbox" id="n88-prototype-video-capable" name="prototype_video_capable" value="1" <?php checked( $existing_profile && $existing_profile->prototype_video_capable == 1 ); ?> required>
