            // Commit 2.3.9.2A: CAD Upload (Operator-only) inside Designer â‡„ Operator thread. Re-run for AJAX-loaded modal content.
            window.n88InitCadUploadForms = function(root) {
                root = root || document;
                var uploadCadForms = root.querySelectorAll ? root.querySelectorAll('.n88-upload-cad-form') : [];
                if (!uploadCadForms.length) return;
                [].forEach.call(uploadCadForms, function(form) {
                var dropzone = form.querySelector('.n88-cad-dropzone');
                var fileInput = form.querySelector('input[type="file"]');
                var submitBtn = form.querySelector('button[type="submit"]');

                var resetDropzoneText = function() {
                    if (dropzone) dropzone.textContent = 'Drag & drop CAD files here (PDF/JPG/PNG) or click to choose';
                };

                if (dropzone && fileInput) {
                    resetDropzoneText();

                    dropzone.addEventListener('click', function() {
                        fileInput.click();
                    });

                    dropzone.addEventListener('dragover', function(e) {
                        e.preventDefault();
                        dropzone.style.backgroundColor = '#0a0a20';
                    });

                    dropzone.addEventListener('dragleave', function() {
                        dropzone.style.backgroundColor = '#05050a';
                    });

                    dropzone.addEventListener('drop', function(e) {
                        e.preventDefault();
                        dropzone.style.backgroundColor = '#05050a';
                        if (e.dataTransfer && e.dataTransfer.files && e.dataTransfer.files.length) {
                            form._cadFiles = e.dataTransfer.files;
                            dropzone.textContent = e.dataTransfer.files.length + ' file(s) selected';
                        }
                    });

                    fileInput.addEventListener('change', function() {
                        if (fileInput.files && fileInput.files.length) {
                            form._cadFiles = fileInput.files;
                            dropzone.textContent = fileInput.files.length + ' file(s) selected';
                        } else {
                            resetDropzoneText();
                        }
                    });
                }

                form.addEventListener('submit', function(e) {
                    e.preventDefault();

                    var paymentId = form.getAttribute('data-payment-id');
                    var itemId = form.getAttribute('data-item-id');
                    var bidId = form.getAttribute('data-bid-id');
                    var files = form._cadFiles || (fileInput ? fileInput.files : null);

                    if (!files || !files.length) {
                        alert('Please select at least one CAD file (PDF/JPG/PNG).');
                        return;
                    }

                    var originalText = submitBtn ? submitBtn.textContent : '';
                    if (submitBtn) {
                        submitBtn.disabled = true;
                        submitBtn.textContent = 'Uploading...';
                    }

                    var formData = new FormData();
                    formData.append('action', 'n88_upload_cad_files');
                    formData.append('payment_id', paymentId);
                    formData.append('item_id', itemId);
                    formData.append('bid_id', bidId);
                    formData.append('_ajax_nonce', '<?php echo esc_js( wp_create_nonce( 'n88_upload_cad_files' ) ); ?>');

                    for (var i = 0; i < files.length; i++) {
                        formData.append('cad_files[]', files[i]);
                    }

                    fetch('<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>', {
                        method: 'POST',
                        body: formData
                    })
                    .then(function(response) { return response.json(); })
                    .then(function(data) {
                        if (data.success) {
                            alert('CAD uploaded as v' + (data.data?.cad_version || '?') + ' (' + (data.data?.file_count || 0) + ' file(s))');
                            // Reset selection UI
                            form._cadFiles = null;
                            if (fileInput) fileInput.value = '';
                            resetDropzoneText();
                            // Reload designer thread messages (case modal uses n88-operator-designer-messages, queue row uses n88-designer-thread-{paymentId})
                            var modalContent = document.getElementById('n88-case-modal-content');
                            var containerId = (modalContent && modalContent.contains && modalContent.contains(form)) ? 'n88-operator-designer-messages' : ('n88-designer-thread-' + paymentId);
                            if (typeof loadThreadMessages === 'function') loadThreadMessages(itemId, 'designer_operator', containerId);
                        } else {
                            alert('Error: ' + (data.data?.message || 'Failed to upload CAD.'));
                        }
                        if (submitBtn) {
                            submitBtn.disabled = false;
                            submitBtn.textContent = originalText;
                        }
                    })
                    .catch(function(error) {
                        console.error('Error uploading CAD:', error);
                        alert('An error occurred. Please try again.');
                        if (submitBtn) {
                            submitBtn.disabled = false;
                            submitBtn.textContent = originalText;
                        }
                    });
                });
                });
            };
            if (document.readyState === 'loading') {
                document.addEventListener('DOMContentLoaded', function() { window.n88InitCadUploadForms(document); });
            } else {
                window.n88InitCadUploadForms(document);
            }

            // Tab switching for operator case modal
            window.n88OperatorCaseSwitchTab = function(idx) {
                var container = document.getElementById('n88-case-modal-content');
                if (!container) return;
                var tabs = container.querySelectorAll('[data-n88-op-tab]');
                var panels = container.querySelectorAll('[data-n88-op-panel]');
                var tabStyle = 'flex: 1; padding: 12px 16px; background: transparent; border: none; border-bottom: 2px solid transparent; color: #888; font-size: 12px; font-weight: 400; cursor: pointer; font-family: monospace;';
                var tabActiveStyle = 'flex: 1; padding: 12px 16px; background: #111111; border: none; border-bottom: 2px solid #FF0065; color: #FF0065; font-size: 12px; font-weight: 600; cursor: pointer; font-family: monospace;';
                for (var i = 0; i < tabs.length; i++) {
                    tabs[i].style.cssText = (i === idx) ? tabActiveStyle : tabStyle;
                }
                // Two-tab mapping:
                // - idx=0: Item Specification tab -> show Item Case(panel 0) + Messages(panel 1)
                // - idx=1: Workflow tab -> show Workflow(panel 2)
                for (var j = 0; j < panels.length; j++) {
                    var panelKey = panels[j].getAttribute('data-n88-op-panel');
                    var show = false;
                    if (idx === 0) {
                        show = (panelKey === '0' || panelKey === '1');
                    } else if (idx === 1) {
                        show = (panelKey === '2');
                    }
                    panels[j].style.display = show ? 'block' : 'none';
                }
                if (idx === 1) {
                    var opWrap = document.getElementById('n88-operator-workflow-timeline-wrap');
                    if (opWrap && opWrap.getAttribute('data-item-id')) {
                        if (typeof window.n88LoadOperatorWorkflowTimeline === 'function') window.n88LoadOperatorWorkflowTimeline();
                        if (typeof window.n88LoadOperatorCaseStep456 === 'function') window.n88LoadOperatorCaseStep456();
                    }
                    if (opWrap) window.n88OperatorWorkflowShowStep(parseInt(opWrap.getAttribute('data-active-step'), 10) || 0);
                }
            };

            // Workflow step switcher: show only the selected step panel; highlight active step (green filled circle + green text), others gray
            window.n88OperatorWorkflowShowStep = function(idx) {
                var wrap = document.getElementById('n88-operator-workflow-timeline-wrap');
                if (!wrap) return;
                idx = parseInt(idx, 10);
                if (isNaN(idx) || idx < 0) idx = 0;
                wrap.setAttribute('data-active-step', String(idx));
                var panels = wrap.querySelectorAll('[data-n88-op-workflow-step]');
                for (var p = 0; p < panels.length; p++) {
                    var stepNum = parseInt(panels[p].getAttribute('data-n88-op-workflow-step'), 10);
                    panels[p].style.display = (stepNum === idx) ? 'block' : 'none';
                }
                var btns = wrap.querySelectorAll('[data-n88-op-workflow-step-btn]');
                var wfGreen = '#FF0065';
                var wfInactive = '#888';
                for (var b = 0; b < btns.length; b++) {
                    var isActive = (parseInt(btns[b].getAttribute('data-n88-op-workflow-step-btn'), 10) === idx);
                    var circle = btns[b].querySelector('.n88-op-step-circle');
                    var lbl = btns[b].querySelector('.n88-op-step-label');
                    if (circle) {
                        circle.style.background = isActive ? wfGreen : '#333';
                        circle.style.borderColor = isActive ? wfGreen : '#555';
                        circle.style.color = isActive ? '#0a0a0a' : wfInactive;
                    }
                    if (lbl) lbl.style.color = isActive ? wfGreen : wfInactive;
                }
            };

            // Load case details via AJAX. opts: { itemId, bidId, openTab } for clarification-only (paymentId 0).
            function loadCaseDetails(paymentId, opts) {
                if (!caseModalContent) return;
                opts = opts || {};

                caseModalContent.innerHTML = '<div style="padding: 40px; text-align: center; color: #999;">Loading case details...</div>';
                if (caseModal) {
                    caseModal.style.display = 'block';
                    document.body.style.overflow = 'hidden';
                    document.body.style.position = 'fixed';
                    document.documentElement.style.overflow = 'hidden';
                }

                var formData = new FormData();
                formData.append('action', 'n88_get_operator_case_details');
                formData.append('payment_id', paymentId || '0');
                if (opts.itemId) formData.append('item_id', opts.itemId);
                if (opts.bidId) formData.append('bid_id', opts.bidId);
                formData.append('_ajax_nonce', '<?php echo esc_js( wp_create_nonce( 'n88_get_operator_case_details' ) ); ?>');

                fetch('<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>', {
                    method: 'POST',
                    body: formData
                })
                .then(function(response) { return response.json(); })
                .then(function(data) {
                    if (data.success && caseModalContent) {
                        caseModalContent.innerHTML = data.data.html;
                        var openTab = (data.data && data.data.open_tab != null) ? parseInt(data.data.open_tab, 10) : 0;
                        window.n88OperatorCaseSwitchTab(openTab);
                        if (typeof window.n88InitCadUploadForms === 'function') window.n88InitCadUploadForms(caseModalContent);
                    } else {
                        if (caseModalContent) {
                            caseModalContent.innerHTML = '<div style="padding: 20px; color: #ff4444;">Error loading case details: ' + (data.data?.message || 'Unknown error') + '</div>';
                        }
                    }
                })
                .catch(function(error) {
                    console.error('Error loading case details:', error);
                    if (caseModalContent) {
                        caseModalContent.innerHTML = '<div style="padding: 20px; color: #ff4444;">Error loading case details. Please try again.</div>';
                    }
                });
            }

            window.n88LoadOperatorWorkflowTimeline = function() {
