                            fd.append('step_id', stId);
                            fd.append('_ajax_nonce', typeof n88OperatorTimelineNonce !== 'undefined' ? n88OperatorTimelineNonce : '');
                            fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' }).then(function(r) { return r.json(); }).then(function(data) {
                                if (!data.success || !data.data) { listEl.innerHTML = 'No evidence'; return; }
                                var arr = data.data.evidence || [];
                                var h = '';
                                var darkBorder = '#555';
                                var darkText = '#ccc';
                                for (var i = 0; i < arr.length; i++) {
                                    var e = arr[i];
                                    var url = e.view_url || e.original_url || '#';
                                    var mt = e.media_type || 'file';
                                    var ca = e.created_at || '';
                                    h += '<div style="margin-bottom:12px; padding:8px; border:1px solid ' + darkBorder + '; border-radius:4px; background:rgba(0,0,0,0.2);">';
                                    if (mt === 'youtube') h += '<div style="margin-bottom:4px;"><a href="' + url.replace(/"/g, '&quot;') + '" target="_blank" rel="noopener" style="color:' + green + ';">YouTube</a> ' + ca + '</div>';
                                    else if (mt === 'image') h += '<div style="margin-bottom:4px;"><a href="' + url.replace(/"/g, '&quot;') + '" target="_blank" rel="noopener" style="color:' + green + ';"><img src="' + url.replace(/"/g, '&quot;') + '" alt="" style="max-width:120px;max-height:80px;object-fit:contain;display:block;"></a> ' + ca + '</div>';
                                    else h += '<div style="margin-bottom:4px;"><a href="' + url.replace(/"/g, '&quot;') + '" target="_blank" rel="noopener" style="color:' + green + ';">' + mt + '</a> ' + ca + '</div>';
                                    if (e.comments && e.comments.length) {
                                        h += '<div style="margin-top:8px; padding-top:8px; border-top:1px solid ' + darkBorder + '; font-size:10px; color:' + darkText + ';">Comments:</div>';
                                        for (var j = 0; j < e.comments.length; j++) {
                                            var c = e.comments[j];
                                            h += '<div style="font-size:11px; color:' + darkText + '; margin-top:4px; white-space:pre-wrap;">' + (c.comment_text || '').replace(/</g, '&lt;').replace(/>/g, '&gt;') + (c.created_at ? '<div style="font-size:10px; opacity:0.8;">' + c.created_at + '</div>' : '') + '</div>';
                                        }
                                    }
                                    h += '</div>';
                                }
                                listEl.innerHTML = h || 'No evidence for this step.';
                            }).catch(function() { listEl.innerHTML = 'Error loading evidence.'; });
                        };
                        wrap.addEventListener('submit', function(ev) {
                            if (ev.target.id !== 'n88-operator-add-evidence-form') return;
                            ev.preventDefault();
                            var form = ev.target;
                            var btn = form.querySelector('#n88-operator-add-evidence-btn');
                            var itId = wrap.getAttribute('data-item-id');
                            var st = wrap._n88StepsData && wrap._n88StepsData[wrap._n88OpSelectedIdx];
                            if (!itId || !st) return;
                            var stepId = st.step_id;
                            var fd = new FormData();
                            fd.append('action', 'n88_upload_timeline_step_evidence');
                            fd.append('_ajax_nonce', typeof n88OperatorEvidenceNonce !== 'undefined' ? n88OperatorEvidenceNonce : '');
                            fd.append('item_id', itId);
                            fd.append('step_id', stepId);
                            var yUrl = (form.querySelector('input[name="youtube_url"]') || {}).value;
                            var fileInput = form.querySelector('input[name="evidence_file"]');
                            if (yUrl && yUrl.trim()) {
                                fd.append('media_type', 'youtube');
                                fd.append('youtube_url', yUrl.trim());
                            } else if (fileInput && fileInput.files && fileInput.files[0]) {
                                fd.append('evidence_file', fileInput.files[0]);
                                var fname = (fileInput.files[0].name || '').toLowerCase();
                                fd.append('media_type', fname.indexOf('.pdf') !== -1 ? 'pdf' : 'image');
                            } else {
                                alert('Please choose a file or enter a YouTube URL.');
                                return;
                            }
                            if (btn) { btn.textContent = 'Uploadingâ€¦'; btn.disabled = true; }
                            fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' }).then(function(r) { return r.json(); }).then(function(data) {
                                var b = form.querySelector('#n88-operator-add-evidence-btn');
                                if (b) { b.textContent = 'Add evidence'; b.disabled = false; }
                                if (data.success) {
                                    if (fileInput) fileInput.value = '';
                                    var yIn = form.querySelector('input[name="youtube_url"]');
                                    if (yIn) yIn.value = '';
                                    if (typeof window.n88LoadOperatorStepEvidence === 'function') window.n88LoadOperatorStepEvidence(itId, stepId);
                                } else {
                                    alert(data.data && data.data.message ? data.data.message : 'Upload failed.');
                                }
                            }).catch(function() {
                                var b = form.querySelector('#n88-operator-add-evidence-btn');
                                if (b) { b.textContent = 'Add evidence'; b.disabled = false; }
                                alert('Upload failed.');
                            });
                        });
                        if (itemId && window.n88LoadOperatorStepEvidence) window.n88LoadOperatorStepEvidence(itemId, steps[0].step_id);
                        wrap.addEventListener('click', function(ev) {
                            if (!ev.target || !ev.target.classList || !ev.target.classList.contains('n88-operator-view-supplier-evidence-btn')) return;
                            var stepId = ev.target.getAttribute('data-step-id');
                            var itemIdClick = wrap.getAttribute('data-item-id');
                            var contentEl = document.getElementById('n88-operator-supplier-evidence-content-' + stepId);
                            if (!contentEl || !itemIdClick) return;
                            contentEl.innerHTML = 'Loadingâ€¦';
                            var fd = new FormData();
                            fd.append('action', 'n88_get_step_evidence');
                            fd.append('item_id', itemIdClick);
                            fd.append('step_id', stepId);
                            fd.append('_ajax_nonce', typeof n88OperatorTimelineNonce !== 'undefined' ? n88OperatorTimelineNonce : '');
                            fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' }).then(function(r) { return r.json(); }).then(function(res) {
                                if (!contentEl) return;
                                if (!res.success || !res.data || !res.data.for_step) { contentEl.innerHTML = 'No data.'; return; }
                                var d = res.data.for_step;
                                var subs = d.submissions || [];
                                var h = '';
                                for (var si = 0; si < subs.length; si++) {
                                    var links = subs[si].links || [];
                                    for (var li = 0; li < links.length; li++) {
                                        var url = (links[li].url || '#').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
                                        var prov = (links[li].provider || 'Link').replace(/</g, '&lt;').replace(/>/g, '&gt;');
                                        h += '<div style="margin-bottom:4px;"><a href="' + url + '" target="_blank" rel="noopener" style="color:' + green + ';">' + prov + '</a></div>';
                                    }
                                }
                                contentEl.innerHTML = h || 'No links.';
                            }).catch(function() { if (contentEl) contentEl.innerHTML = 'Error loading.'; });
                        });
                        wrap.setAttribute('data-timeline-loaded', '1');
                    })
                    .catch(function(err) {
                        container.innerHTML = '<div style="padding: 12px; color: #cc6666; font-size: 12px;">Failed to load timeline.</div>';
                    });
            };

            // Commit 3.B.5.A1: Load Step 4-6 Video + Designer Comments for operator case view (dynamic panels)
            window.n88LoadOperatorCaseStep456 = function() {
                var wrap = document.getElementById('n88-operator-workflow-timeline-wrap');
                if (!wrap) return;
                var itemId = wrap.getAttribute('data-item-id');
                if (!itemId) return;
                var containers = [document.getElementById('n88-op-step456-content-4'), document.getElementById('n88-op-step456-content-5'), document.getElementById('n88-op-step456-content-6')];
                if (!containers[0] && !containers[1] && !containers[2]) return;
                var green = '#FF0065';
                var darkText = '#ccc';
                var darkBorder = '#555';
                var nonce = typeof n88OperatorTimelineNonce !== 'undefined' ? n88OperatorTimelineNonce : '';
                var evNonce = typeof n88OperatorEvidenceNonce !== 'undefined' ? n88OperatorEvidenceNonce : '';
                var ajaxUrl = '<?php echo esc_url( admin_url( "admin-ajax.php" ) ); ?>';
                for (var c = 0; c < containers.length; c++) {
                    if (containers[c]) containers[c].innerHTML = 'Loadingâ€¦';
                }
                var fd = new FormData();
                fd.append('action', 'n88_get_item_timeline');
                fd.append('item_id', itemId);
                fd.append('_ajax_nonce', nonce);
                fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (!data.success || !data.data) {
                            for (var c = 0; c < containers.length; c++) {
                                if (containers[c]) containers[c].innerHTML = '<div style="color:#cc6666;font-size:11px;">Failed to load.</div>';
                            }
                            return;
                        }
                        var t = data.data.timeline || {};
                        var steps = t.steps || [];
                        var step456Videos = data.data.step_456_videos || { 4: [], 5: [], 6: [] };
                        var step456Comments = data.data.step_456_comments || { 4: [], 5: [], 6: [] };
                        var stepNumMap = [4, 5, 6];
                        for (var i = 0; i < 3; i++) {
                            var stepNum = stepNumMap[i];
                            var cont = containers[i];
                            if (!cont) continue;
                            var stepData = steps.filter(function(s) { return (s.step_number || s.step_id) == stepNum; })[0] || {};
                            var videos = step456Videos[stepNum] || [];
                            var comments = step456Comments[stepNum] || [];
                            var status = stepData.status || 'pending';
                            var hasEvidence = stepData.has_required_evidence !== false;
                            var h = '';
                            h += '<div style="font-size:12px;font-weight:600;color:' + green + ';margin-bottom:8px;">Video Submissions</div>';
                            if (videos.length > 0) {
                                for (var vi = 0; vi < videos.length; vi++) {
                                    var sub = videos[vi];
                                    h += '<div style="font-size:11px;color:' + darkText + ';margin-bottom:6px;">v' + (sub.version || '') + '  ' + (sub.source === 'operator' ? 'Operator' : 'Supplier') + '</div>';
                                    if (sub.optional_note) h += '<div style="font-size:11px;color:#888;font-style:italic;margin-bottom:4px;">' + (sub.optional_note || '').replace(/</g, '&lt;').replace(/>/g, '&gt;') + '</div>';
                                    if (sub.links && sub.links.length) {
                                        h += '<ul style="margin:0 0 8px 18px;padding:0;font-size:11px;">';
                                        for (var li = 0; li < sub.links.length; li++) {
                                            var lk = sub.links[li];
                                            h += '<li><a href="' + (lk.url || '').replace(/"/g, '&quot;') + '" target="_blank" rel="noopener noreferrer" style="color:' + green + ';">' + (lk.provider || 'Link') + '</a></li>';
                                        }
                                        h += '</ul>';
                                    }
                                }
                            } else {
                                h += '<div style="font-size:11px;color:' + darkText + ';margin-bottom:10px;">No video submissions yet.</div>';
                            }
                            h += '<button type="button" class="n88-op-attach-video-btn" data-step="' + stepNum + '" style="padding:6px 12px;font-size:11px;background:#111;color:' + green + ';border:1px solid ' + green + ';border-radius:4px;cursor:pointer;font-family:monospace;margin-bottom:12px;">Attach video link</button>';
                            h += '<div id="n88-op-attach-form-' + stepNum + '" style="display:none;margin-bottom:12px;padding:10px;border:1px solid ' + darkBorder + ';border-radius:4px;background:rgba(0,0,0,0.2);">';
                            h += '<input type="url" id="n88-op-video-url1-' + stepNum + '" placeholder="Video URL 1 (YouTube/Vimeo/Loom)" style="width:100%;padding:6px;margin-bottom:6px;font-size:11px;background:#111;color:#ccc;border:1px solid ' + darkBorder + ';border-radius:4px;">';
                            h += '<input type="url" id="n88-op-video-url2-' + stepNum + '" placeholder="URL 2 (optional)" style="width:100%;padding:6px;margin-bottom:6px;font-size:11px;background:#111;color:#ccc;border:1px solid ' + darkBorder + ';border-radius:4px;">';
                            h += '<input type="url" id="n88-op-video-url3-' + stepNum + '" placeholder="URL 3 (optional)" style="width:100%;padding:6px;margin-bottom:8px;font-size:11px;background:#111;color:#ccc;border:1px solid ' + darkBorder + ';border-radius:4px;">';
                            h += '<textarea id="n88-op-video-note-' + stepNum + '" placeholder="Optional note" rows="2" style="width:100%;padding:6px;margin-bottom:8px;font-size:11px;background:#111;color:#ccc;border:1px solid ' + darkBorder + ';border-radius:4px;resize:vertical;"></textarea>';
                            h += '<div style="display:flex;gap:8px;"><button type="button" class="n88-op-attach-submit" data-step="' + stepNum + '" style="padding:6px 12px;font-size:11px;background:' + green + ';color:#000;border:none;border-radius:4px;cursor:pointer;">Submit</button>';
                            h += '<button type="button" class="n88-op-attach-cancel" data-step="' + stepNum + '" style="padding:6px 12px;font-size:11px;background:transparent;color:' + darkText + ';border:1px solid ' + darkBorder + ';border-radius:4px;cursor:pointer;">Cancel</button></div></div>';
                            h += '<div style="font-size:12px;font-weight:600;color:' + green + ';margin-top:12px;margin-bottom:8px;">Designer Comments</div>';
                            if (comments.length > 0) {
                                h += '<ul style="margin:0;padding-left:18px;font-size:11px;color:' + darkText + ';">';
                                for (var ci = 0; ci < comments.length; ci++) {
                                    var cm = comments[ci];
                                    h += '<li style="margin-bottom:6px;">' + (cm.created_at || '').split(' ')[0] + ' ' + (cm.designer_name || '') + ': &quot;' + (cm.comment_text || '').replace(/</g, '&lt;').replace(/>/g, '&gt;') + '&quot;</li>';
                                }
                                h += '</ul>';
                            } else {
                                h += '<div style="font-size:11px;color:' + darkText + ';margin-bottom:10px;">No designer comments yet.</div>';
                            }
                            h += '<div style="margin-top:12px;display:flex;gap:8px;flex-wrap:wrap;">';
                            if (status === 'pending') {
                                h += '<button type="button" class="n88-op-start-step-btn" data-step="' + stepNum + '" style="padding:6px 12px;background:' + green + ';color:#000;border:none;border-radius:4px;font-size:12px;font-weight:600;cursor:pointer;font-family:monospace;">Start Step</button>';
                            } else if (status === 'in_progress') {
                                h += '<button type="button" class="n88-op-complete-step-btn" data-step="' + stepNum + '" data-has-evidence="' + (hasEvidence ? '1' : '0') + '" style="padding:6px 12px;background:' + (hasEvidence ? green : '#333') + ';color:' + (hasEvidence ? '#000' : '#666') + ';border:none;border-radius:4px;font-size:12px;font-weight:600;cursor:' + (hasEvidence ? 'pointer' : 'not-allowed') + ';font-family:monospace;"' + (hasEvidence ? '' : ' disabled title="Evidence required to complete."') + '>Mark Completed</button>';
                            }
                            h += '</div>';
                            cont.innerHTML = h;
                        }
                        if (wrap._n88Step456ClickListener) return;
                        wrap._n88Step456ClickListener = true;
                        wrap.addEventListener('click', function(ev) {
                            var tg = ev.target;
                            if (!tg || !tg.classList) return;
                            if (tg.classList.contains('n88-op-attach-video-btn')) {
                                var step = tg.getAttribute('data-step');
                                var formEl = document.getElementById('n88-op-attach-form-' + step);
                                if (formEl) formEl.style.display = formEl.style.display === 'none' ? 'block' : 'none';
                                return;
                            }
                            if (tg.classList.contains('n88-op-attach-cancel')) {
                                var step = tg.getAttribute('data-step');
                                var formEl = document.getElementById('n88-op-attach-form-' + step);
                                if (formEl) formEl.style.display = 'none';
                                return;
                            }
                            if (tg.classList.contains('n88-op-attach-submit')) {
                                var step = parseInt(tg.getAttribute('data-step'), 10);
                                var u1 = (document.getElementById('n88-op-video-url1-' + step) || {}).value || '';
                                var u2 = (document.getElementById('n88-op-video-url2-' + step) || {}).value || '';
                                var u3 = (document.getElementById('n88-op-video-url3-' + step) || {}).value || '';
                                var urls = [u1, u2, u3].filter(function(x) { return x.trim(); });
                                if (urls.length < 1 || urls.length > 3) { alert('Enter 1 to 3 video links (YouTube, Vimeo, Loom).'); return; }
                                var note = (document.getElementById('n88-op-video-note-' + step) || {}).value || '';
                                tg.disabled = true;
                                tg.textContent = 'Submittingâ€¦';
                                var f = new FormData();
                                f.append('action', 'n88_operator_add_step_video');
                                f.append('item_id', itemId);
                                f.append('step_number', String(step));
                                f.append('_ajax_nonce', evNonce);
                                if (urls[0]) f.append('url_1', urls[0]); if (urls[1]) f.append('url_2', urls[1]); if (urls[2]) f.append('url_3', urls[2]);
                                if (note) f.append('optional_note', note);
                                fetch(ajaxUrl, { method: 'POST', body: f, credentials: 'same-origin' }).then(function(r) { return r.json(); }).then(function(res) {
                                    tg.disabled = false;
                                    tg.textContent = 'Submit';
                                    if (res.success) {
                                        document.getElementById('n88-op-attach-form-' + step).style.display = 'none';
                                        if (typeof window.n88LoadOperatorCaseStep456 === 'function') window.n88LoadOperatorCaseStep456();
                                    } else {
                                        alert((res.data && res.data.message) || res.message || 'Failed.');
                                    }
                                }).catch(function() { tg.disabled = false; tg.textContent = 'Submit'; alert('Failed.'); });
                                return;
                            }
                            if (tg.classList.contains('n88-op-start-step-btn')) {
                                var step = parseInt(tg.getAttribute('data-step'), 10);
                                tg.disabled = true;
                                var f = new FormData();
                                f.append('action', 'n88_timeline_start_step');
                                f.append('item_id', itemId);
                                f.append('step_number', String(step));
                                f.append('_ajax_nonce', nonce);
                                fetch(ajaxUrl, { method: 'POST', body: f, credentials: 'same-origin' }).then(function(r) { return r.json(); }).then(function(res) {
                                    if (res.success && typeof window.n88LoadOperatorCaseStep456 === 'function') window.n88LoadOperatorCaseStep456();
                                    else if (!res.success) alert(res.message || 'Failed.');
                                    tg.disabled = false;
                                }).catch(function() { tg.disabled = false; });
                                return;
                            }
                            if (tg.classList.contains('n88-op-complete-step-btn')) {
                                var step = parseInt(tg.getAttribute('data-step'), 10);
                                if (tg.getAttribute('data-has-evidence') !== '1') return;
                                tg.disabled = true;
                                var f = new FormData();
                                f.append('action', 'n88_timeline_complete_step');
                                f.append('item_id', itemId);
                                f.append('step_number', String(step));
                                f.append('evidence_override', '0');
                                f.append('_ajax_nonce', nonce);
                                fetch(ajaxUrl, { method: 'POST', body: f, credentials: 'same-origin' }).then(function(r) { return r.json(); }).then(function(res) {
                                    if (res.success && typeof window.n88LoadOperatorCaseStep456 === 'function') window.n88LoadOperatorCaseStep456();
                                    else if (!res.success) alert((res.data && res.data.message) || res.message || 'Failed.');
                                    tg.disabled = false;
                                }).catch(function() { tg.disabled = false; });
                                return;
                            }
                        });
                    })
                    .catch(function() {
                        for (var c = 0; c < containers.length; c++) {
                            if (containers[c]) containers[c].innerHTML = '<div style="color:#cc6666;font-size:11px;">Failed to load timeline.</div>';
                        }
                    });
            };

            // Commit 2.3.9.1D: Mark Payment Received with Confirmation Modal
            var paymentConfirmModal = document.getElementById('n88-payment-confirm-modal');
            var closePaymentConfirmModal = document.getElementById('n88-close-payment-confirm-modal');
            var cancelPaymentConfirm = document.getElementById('n88-cancel-payment-confirm');
            var confirmPaymentReceived = document.getElementById('n88-confirm-payment-received');
            var currentPaymentBtn = null;
            
            // Close modal handlers
            if (closePaymentConfirmModal) {
                closePaymentConfirmModal.addEventListener('click', function() {
                    if (paymentConfirmModal) paymentConfirmModal.style.display = 'none';
                });
            }
            
            if (cancelPaymentConfirm) {
                cancelPaymentConfirm.addEventListener('click', function() {
                    if (paymentConfirmModal) paymentConfirmModal.style.display = 'none';
                });
            }
            
            // Click outside modal to close
            if (paymentConfirmModal) {
                paymentConfirmModal.addEventListener('click', function(e) {
                    if (e.target === paymentConfirmModal) {
                        paymentConfirmModal.style.display = 'none';
                    }
                });
            }
            
            // Mark Payment Received / View Payment  delegated so AJAX-loaded case modal buttons work
            document.addEventListener('click', function(e) {
                var btn = e.target && e.target.closest ? e.target.closest('.n88-mark-payment-received-btn, .n88-operator-view-payment-btn') : null;
                if (!btn) return;
                e.stopPropagation();
                var paymentId = btn.getAttribute('data-payment-id');
                var itemId = btn.getAttribute('data-item-id');
                var bidId = btn.getAttribute('data-bid-id');
                var totalDue = btn.getAttribute('data-total-due');
                document.getElementById('n88-confirm-item-id').textContent = itemId || '';
                document.getElementById('n88-confirm-bid-id').textContent = bidId || '';
                document.getElementById('n88-confirm-total-due').textContent = '$' + parseFloat(totalDue || 0).toFixed(2);
                currentPaymentBtn = btn;
                currentPaymentBtn.paymentId = paymentId;
                currentPaymentBtn.itemId = itemId;
                currentPaymentBtn.bidId = bidId;
                if (paymentConfirmModal) paymentConfirmModal.style.display = 'block';
                var listEl = document.getElementById('n88-receipts-list');
                if (listEl) {
                    listEl.textContent = 'Loadingâ€¦';
                    var fd = new FormData();
                    fd.append('action', 'n88_get_payment_receipts');
                    fd.append('payment_id', paymentId);
                    fd.append('_ajax_nonce', '<?php echo esc_js( wp_create_nonce( 'n88_get_payment_receipts' ) ); ?>');
                    fetch('<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>', { method: 'POST', body: fd })
                        .then(function(r) { return r.json(); })
                        .then(function(d) {
                            if (!listEl) return;
                            if (d.success && d.data.receipts && d.data.receipts.length > 0) {
                                var receipts = d.data.receipts;
                                var parts = receipts.map(function(x, index) {
                                    var isResubmitted = receipts.length > 1 && index < receipts.length - 1;
                                    var tag = isResubmitted ? '<span style="display:inline-block;margin-right:8px;padding:2px 6px;font-size:10px;font-weight:600;background-color:#331100;color:#ff8800;border:1px solid #ff8800;border-radius:2px;">Resubmitted</span>' : '';
                                    var name = (x.file_name || 'file').replace(/</g,'&lt;').replace(/>/g,'&gt;');
                                    var msg = (x.message && String(x.message).trim()) ? ' <span style="color:#aaa;font-style:italic;display:block;margin-top:2px;"> ' + String(x.message).replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</span>' : '';
                                    return '<div style="margin-bottom:6px;">' + tag + '<a href="' + (x.url || '#') + '" target="_blank" rel="noopener" style="color:#FF0065">' + name + '</a>' + msg + '</div>';
                                });
                                listEl.innerHTML = parts.join('');
                            } else {
                                listEl.textContent = 'None uploaded.';
                            }
                        })
                        .catch(function() { if (listEl) listEl.textContent = ''; });
                }
            });

            // Commit 2.3.9.2A: Release Approved CAD to Supplier Modal
            var releaseCadModal = document.getElementById('n88-release-cad-modal');
            var closeReleaseCadModal = document.getElementById('n88-close-release-cad-modal');
            var cancelReleaseCad = document.getElementById('n88-cancel-release-cad');
            var confirmReleaseCad = document.getElementById('n88-confirm-release-cad');
            var currentReleaseBtn = null;

            if (closeReleaseCadModal) {
                closeReleaseCadModal.addEventListener('click', function() {
                    if (releaseCadModal) releaseCadModal.style.display = 'none';
                });
            }
            if (cancelReleaseCad) {
                cancelReleaseCad.addEventListener('click', function() {
                    if (releaseCadModal) releaseCadModal.style.display = 'none';
                });
            }
            if (releaseCadModal) {
                releaseCadModal.addEventListener('click', function(e) {
                    if (e.target === releaseCadModal) {
                        releaseCadModal.style.display = 'none';
                    }
                });
            }

            // Release CAD  delegated so AJAX-loaded case modal buttons work
            document.addEventListener('click', function(e) {
                var btn = e.target && e.target.closest ? e.target.closest('.n88-release-cad-btn') : null;
                if (!btn) return;
                e.stopPropagation();
                currentReleaseBtn = btn;
                var paymentId = btn.getAttribute('data-payment-id');
                var itemId = btn.getAttribute('data-item-id');
                var bidId = btn.getAttribute('data-bid-id');
                var supplierId = btn.getAttribute('data-supplier-id');
                var approvedVersion = btn.getAttribute('data-approved-version');
                document.getElementById('n88-release-item-id').textContent = itemId || '';
                document.getElementById('n88-release-bid-id').textContent = bidId || '';
                document.getElementById('n88-release-supplier-id').textContent = supplierId || '';
                document.getElementById('n88-release-approved-version').textContent = 'v' + (approvedVersion || '?');
                currentReleaseBtn.paymentId = paymentId;
                if (releaseCadModal) releaseCadModal.style.display = 'block';
            });

            if (confirmReleaseCad) {
                confirmReleaseCad.addEventListener('click', function() {
                    if (!currentReleaseBtn) return;

                    var paymentId = currentReleaseBtn.paymentId;

                    confirmReleaseCad.disabled = true;
                    var originalText = confirmReleaseCad.textContent;
                    confirmReleaseCad.textContent = 'Releasing...';

                    var formData = new FormData();
                    formData.append('action', 'n88_release_cad_to_supplier');
                    formData.append('payment_id', paymentId);
                    formData.append('_ajax_nonce', '<?php echo esc_js( wp_create_nonce( 'n88_release_cad_to_supplier' ) ); ?>');

                    fetch('<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>', {
                        method: 'POST',
                        body: formData
                    })
                    .then(function(response) { return response.json(); })
                    .then(function(data) {
                        if (data.success) {
                            if (releaseCadModal) releaseCadModal.style.display = 'none';
                            alert('Approved CAD released to supplier.');
                            // Refresh page to update button visibility and counts
                            window.location.reload();
                        } else {
                            alert('Error: ' + (data.data?.message || 'Failed to release CAD.'));
                        }
                        confirmReleaseCad.disabled = false;
                        confirmReleaseCad.textContent = originalText;
                    })
                    .catch(function(error) {
                        console.error('Error releasing CAD:', error);
                        alert('An error occurred. Please try again.');
                        confirmReleaseCad.disabled = false;
                        confirmReleaseCad.textContent = originalText;
                    });
                });
            }
            
            // Confirm Payment Received button in modal
            if (confirmPaymentReceived) {
                confirmPaymentReceived.addEventListener('click', function() {
                    if (!currentPaymentBtn) return;
                    
                    var paymentId = currentPaymentBtn.paymentId;
                    var itemId = currentPaymentBtn.itemId;
                    var bidId = currentPaymentBtn.bidId;
                    var btn = currentPaymentBtn;
                    
                    // Close modal
                    if (paymentConfirmModal) paymentConfirmModal.style.display = 'none';
                    
                    // Disable button and show processing
                    var originalText = btn.textContent;
                    btn.disabled = true;
                    btn.textContent = '[ Processing... ]';
                    
                    var formData = new FormData();
                    formData.append('action', 'n88_mark_payment_received');
                    formData.append('payment_id', paymentId);
                    formData.append('item_id', itemId);
                    formData.append('bid_id', bidId);
                    formData.append('_ajax_nonce', '<?php echo esc_js( wp_create_nonce( 'n88_mark_payment_received' ) ); ?>');
                    
                    fetch('<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>', {
                        method: 'POST',
                        body: formData
                    })
                    .then(function(response) { return response.json(); })
                    .then(function(data) {
                        if (data.success) {
                            if (btn.classList && btn.classList.contains('n88-operator-view-payment-btn')) {
                                if (typeof loadCaseDetails === 'function') loadCaseDetails(paymentId, { openTab: 1 });
                            } else {
                                btn.style.backgroundColor = '#001100';
                                btn.style.borderColor = '#FF0065';
                                btn.style.color = '#FF0065';
                                btn.textContent = ' Payment Confirmed';
                                btn.disabled = true;
                                var statusCell = btn.closest('tr') && btn.closest('tr').previousElementSibling ? btn.closest('tr').previousElementSibling.querySelector('td:nth-child(4)') : null;
                                if (statusCell) {
                                    statusCell.innerHTML = '<div>Payment Received</div><div style="font-size: 11px; color: #FF0065;">Confirmed</div>';
                                }
                                setTimeout(function() { window.location.reload(); }, 2000);
                            }
                        } else {
                            alert('Error: ' + (data.data?.message || 'Failed to mark payment as received.'));
                            btn.disabled = false;
                            btn.textContent = originalText;
                        }
                    })
                    .catch(function(error) {
                        console.error('Error marking payment as received:', error);
                        alert('An error occurred. Please try again.');
                        btn.disabled = false;
                        btn.textContent = originalText;
                    });
                    
                    // Reset reference
                    currentPaymentBtn = null;
                });
            }
            
            // Auto-refresh every 30 seconds
            var autoRefreshInterval = setInterval(function() {
                // Only refresh if no modal is open and no filters are being edited
                if (!caseModal || caseModal.style.display === 'none') {
                    // Soft refresh - just reload the page
                    // In future, could be AJAX-based
                }
            }, 30000);
            
            // Commit 2.3.9.1C-a: Send Operator Message
            window.sendOperatorMessage = function(event, threadType, itemId, designerId, bidId, supplierId) {
                event.preventDefault();
                
                var form = event.target;
                var messageInput = form.querySelector('textarea[name="message_text"]') || form.querySelector('input[name="message_text"]');
                var messageText = messageInput ? messageInput.value.trim() : '';
                
                if (!messageText) {
                    alert('Please enter a message.');
                    return false;
                }
                
                var submitBtn = form.querySelector('button[type="submit"]');
                var originalText = submitBtn ? submitBtn.textContent : '';
                if (submitBtn) {
                    submitBtn.disabled = true;
                    submitBtn.textContent = '[ Sending... ]';
                }
                
                var formData = new FormData();
                formData.append('action', 'n88_send_item_message');
                formData.append('item_id', itemId);
                formData.append('thread_type', threadType);
                formData.append('message_text', messageText);
                if (designerId) formData.append('designer_id', designerId);
                if (bidId) formData.append('bid_id', bidId);
                if (supplierId) formData.append('supplier_id', supplierId);
                formData.append('_ajax_nonce', '<?php echo esc_js( wp_create_nonce( 'n88_send_item_message' ) ); ?>');
                
                fetch('<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>', {
                    method: 'POST',
                    body: formData
                })
                .then(function(response) { return response.json(); })
                .then(function(data) {
                    if (data.success) {
                        // Clear form
                        if (messageInput) messageInput.value = '';
                        
                        // Reload case details to show new message
                        var paymentId = form.getAttribute('data-payment-id');
                        if (paymentId && paymentId !== '0') {
                            loadCaseDetails(paymentId);
                        } else {
                            var itemId = form.getAttribute('data-item-id');
                            var bidId = form.getAttribute('data-bid-id') || '0';
                            if (itemId) {
                                loadCaseDetails(0, { itemId: itemId, bidId: bidId, openTab: 0 });
                            } else {
                                location.reload();
                            }
                        }
                    } else {
                        alert('Error: ' + (data.data?.message || 'Failed to send message. Please try again.'));
                    }
                    
                    // Re-enable form
                    if (submitBtn) {
                        submitBtn.disabled = false;
                        submitBtn.textContent = originalText;
                    }
                })
                .catch(function(error) {
                    console.error('Error sending message:', error);
                    alert('An error occurred. Please try again.');
                    if (submitBtn) {
                        submitBtn.disabled = false;
                        submitBtn.textContent = originalText;
                    }
                });
                
                return false;
            };
            
            // Commit 2.3.9.1C-a: Copy Message to Other Side
            window.copyMessageToOtherSide = function(itemId, designerId, bidId, supplierId, paymentId) {
                // Get the last message from designer thread
                var designerMessages = document.getElementById('n88-operator-designer-messages');
                var supplierMessages = document.getElementById('n88-operator-supplier-messages');
                
                if (!designerMessages || !supplierMessages) {
                    alert('Message threads not found.');
                    return;
                }
                
                // Find last message in designer thread
                var designerLastMsg = designerMessages.querySelector('div[style*="margin-bottom: 12px"]:last-child');
                if (!designerLastMsg) {
                    alert('No messages in designer thread to copy.');
                    return;
                }
                
                var msgText = designerLastMsg.querySelector('div[style*="white-space: pre-wrap"]');
                if (!msgText) {
                    alert('Could not extract message text.');
                    return;
                }
                
                var textToCopy = msgText.textContent.trim();
                if (!textToCopy) {
                    alert('Message text is empty.');
                    return;
                }
                
                // Confirm action
                if (!confirm('Copy this message to the supplier thread?\n\n"' + textToCopy.substring(0, 100) + (textToCopy.length > 100 ? '...' : '') + '"')) {
                    return;
                }
                
                // Send to supplier thread
                var formData = new FormData();
                formData.append('action', 'n88_send_item_message');
                formData.append('item_id', itemId);
                formData.append('thread_type', 'supplier_operator');
                formData.append('message_text', textToCopy);
                formData.append('bid_id', bidId);
                formData.append('supplier_id', supplierId);
                formData.append('_ajax_nonce', '<?php echo esc_js( wp_create_nonce( 'n88_send_item_message' ) ); ?>');
                
                fetch('<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>', {
                    method: 'POST',
                    body: formData
                })
                .then(function(response) { return response.json(); })
                .then(function(data) {
                    if (data.success) {
                        alert('Message copied to supplier thread.');
                        // Reload case details
                        if (paymentId) {
                            loadCaseDetails(paymentId);
                        } else {
                            location.reload();
                        }
                    } else {
                        alert('Error: ' + (data.data?.message || 'Failed to copy message.'));
                    }
                })
                .catch(function(error) {
                    console.error('Error copying message:', error);
                    alert('An error occurred. Please try again.');
                });
            };
        })();
        </script>
        <?php
        return ob_get_clean();
    }

    /**
     * Render operator case message body: text + file links as "View" with optional image placeholder (opens in new tab).
     *
     * @param string $message_text Raw message text (may contain "Files:" / "CAD Files:" and "- name: url" lines).
     * @return string HTML-safe body (escaped text + file cards with View link).
     */
    private function n88_render_operator_message_body( $message_text ) {
        $text = is_string( $message_text ) ? $message_text : '';
        $files = array();
        $files_label = '';
        if ( preg_match( '/\n\s*(CAD Files:|Files:)\s*\n/i', $text, $m ) ) {
            $files_label = trim( $m[1] );
            $parts = preg_split( '/\n\s*(?:CAD Files:|Files:)\s*\n/i', $text, 2 );
            $text = isset( $parts[0] ) ? trim( $parts[0] ) : $text;
            $rest = isset( $parts[1] ) ? $parts[1] : '';
            $lines = preg_split( '/\r\n|\n/', $rest );
            foreach ( $lines as $line ) {
                $line = trim( $line );
                if ( strpos( $line, '- ' ) === 0 ) {
                    $after = substr( $line, 2 );
                    $sep = strpos( $after, ': ' );
                    if ( $sep > 0 ) {
                        $name = trim( substr( $after, 0, $sep ) );
                        $url  = trim( substr( $after, $sep + 2 ) );
                        if ( preg_match( '#^https?://#i', $url ) ) {
                            $ext = pathinfo( $name, PATHINFO_EXTENSION );
                            $files[] = array( 'name' => $name, 'url' => $url, 'ext' => strtolower( $ext ) );
                        }
                    }
                }
            }
        }
        $out = nl2br( esc_html( $text ) );
        if ( ! empty( $files ) ) {
            $out .= '<div style="margin-top: 10px; padding-top: 10px; border-top: 1px solid #333; display: flex; flex-direction: column; gap: 6px;">';
            foreach ( $files as $f ) {
                $url_attr = esc_url( $f['url'] );
                $name_esc = esc_html( $f['name'] );
                $is_img = in_array( $f['ext'], array( 'jpg', 'jpeg', 'png', 'gif', 'webp' ), true );
                $out .= '<a href="' . $url_attr . '" target="_blank" rel="noopener noreferrer" style="display: inline-flex; align-items: center; gap: 8px; padding: 6px 10px; background: #0a0a0a; border: 1px solid #555; border-radius: 4px; text-decoration: none; color: #FF0065; font-size: 11px; max-width: 100%;" onmouseover="this.style.borderColor=\'#FF0065\';" onmouseout="this.style.borderColor=\'#555\';" title="Click to open in new tab">';
                if ( $is_img ) {
                    $out .= '<img src="' . $url_attr . '" alt="" style="width: 40px; height: 40px; object-fit: contain; border-radius: 4px; flex-shrink: 0; background: #000;">';
                } else {
                    $out .= '<span style="flex-shrink: 0;">ðŸ“„</span>';
                }
                $out .= '<span style="overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">' . $name_esc . '</span><span style="flex-shrink: 0;">View â†’</span></a>';
            }
            $out .= '</div>';
        }
        return $out;
    }

        /**
         * Clarification-only case: no payment; load by item_id + bid_id and return modal HTML with open_tab=0 (Item Specification).
         */
    private function ajax_get_operator_case_details_clarification_only( $item_id, $bid_id ) {
        global $wpdb;
        $items_table = $wpdb->prefix . 'n88_items';
        $item_bids_table = $wpdb->prefix . 'n88_item_bids';
        $categories_table = $wpdb->prefix . 'n88_categories';
        $users_table = $wpdb->prefix . 'users';
        $messages_table = $wpdb->prefix . 'n88_item_messages';

        $item = $wpdb->get_row( $wpdb->prepare(
            "SELECT i.id, i.title, i.primary_image_id, i.item_type, i.owner_user_id
             FROM {$items_table} i WHERE i.id = %d",
            $item_id
        ), ARRAY_A );
        if ( ! $item ) {
            wp_send_json_error( array( 'message' => 'Item not found.' ) );
            return;
        }

        $thumbnail_url = '';
        if ( ! empty( $item['primary_image_id'] ) ) {
            $thumbnail_url = wp_get_attachment_image_url( $item['primary_image_id'], 'thumbnail' );
            if ( ! $thumbnail_url ) {
                $thumbnail_url = wp_get_attachment_url( $item['primary_image_id'] );
            }
        }
        $category_name = ! empty( $item['item_type'] ) ? $item['item_type'] : 'Uncategorized';
        if ( ! empty( $item['item_type'] ) ) {
            $cat = $wpdb->get_row( $wpdb->prepare(
                "SELECT name FROM {$categories_table} WHERE category_id = %d OR name = %s LIMIT 1",
                intval( $item['item_type'] ),
                $item['item_type']
            ), ARRAY_A );
            if ( $cat ) {
                $category_name = $cat['name'];
            }
        }

        // Delivery context + item meta (same as payment case)
        $delivery_country = '';
        $delivery_postal = '';
        $item_quantity = '';
        $dimensions_summary = '';
        $delivery_quoting_note = '';
        $item_delivery_context_table = $wpdb->prefix . 'n88_item_delivery_context';
        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$item_delivery_context_table}'" ) === $item_delivery_context_table ) {
            $delivery_cols = $wpdb->get_col( "DESCRIBE {$item_delivery_context_table}" );
            $sel = array( 'delivery_country_code', 'delivery_postal_code' );
            if ( in_array( 'quantity', $delivery_cols, true ) ) {
                $sel[] = 'quantity';
            }
            if ( in_array( 'dimensions_json', $delivery_cols, true ) ) {
                $sel[] = 'dimensions_json';
            }
            if ( in_array( 'delivery_cost_usd', $delivery_cols, true ) ) {
                $sel[] = 'delivery_cost_usd';
            }
            if ( in_array( 'shipping_estimate_mode', $delivery_cols, true ) ) {
                $sel[] = 'shipping_estimate_mode';
            }
            $delivery_row = $wpdb->get_row( $wpdb->prepare(
                "SELECT " . implode( ', ', $sel ) . " FROM {$item_delivery_context_table} WHERE item_id = %d",
                $item_id
            ), ARRAY_A );
            if ( $delivery_row ) {
                $delivery_country = isset( $delivery_row['delivery_country_code'] ) ? $delivery_row['delivery_country_code'] : '';
                $delivery_postal = isset( $delivery_row['delivery_postal_code'] ) ? $delivery_row['delivery_postal_code'] : '';
                if ( isset( $delivery_row['quantity'] ) && $delivery_row['quantity'] !== null && $delivery_row['quantity'] !== '' ) {
                    $item_quantity = $delivery_row['quantity'];
                }
                if ( ! empty( $delivery_row['dimensions_json'] ) ) {
                    $dims = json_decode( $delivery_row['dimensions_json'], true );
                    if ( is_array( $dims ) ) {
                        $w = isset( $dims['width'] ) ? $dims['width'] : ( isset( $dims['w'] ) ? $dims['w'] : '' );
                        $d = isset( $dims['depth'] ) ? $dims['depth'] : ( isset( $dims['d'] ) ? $dims['d'] : '' );
                        $h = isset( $dims['height'] ) ? $dims['height'] : ( isset( $dims['h'] ) ? $dims['h'] : '' );
                        $u = isset( $dims['unit'] ) ? $dims['unit'] : '';
                        $dimensions_summary = trim( ( $w !== '' ? $w : '' ) . ' Ã— ' . ( $d !== '' ? $d : '' ) . ' Ã— ' . ( $h !== '' ? $h : '' ) . ( $u !== '' ? ' ' . $u : '' ), ' Ã—' );
                        if ( $dimensions_summary === ' Ã—  Ã— ' ) {
                            $dimensions_summary = '';
                        }
                    }
                }
                if ( isset( $delivery_row['delivery_cost_usd'] ) && $delivery_row['delivery_cost_usd'] !== null && $delivery_row['delivery_cost_usd'] !== '' && floatval( $delivery_row['delivery_cost_usd'] ) > 0 ) {
                    $delivery_quoting_note = 'Delivery (quoted): $' . number_format( floatval( $delivery_row['delivery_cost_usd'] ), 2 );
                } elseif ( isset( $delivery_row['shipping_estimate_mode'] ) && $delivery_row['shipping_estimate_mode'] === 'auto' ) {
                    $delivery_quoting_note = 'Shipping: instant estimate';
                } else {
                    $delivery_quoting_note = 'Shipping: manual quote';
                }
            }
        }
        if ( $item_quantity === '' ) {
            $item_row = $wpdb->get_row( $wpdb->prepare(
                "SELECT meta_json FROM {$items_table} WHERE id = %d",
                $item_id
            ), ARRAY_A );
            if ( $item_row && ! empty( $item_row['meta_json'] ) ) {
                $meta = json_decode( $item_row['meta_json'], true );
                if ( is_array( $meta ) && isset( $meta['quantity'] ) ) {
                    $item_quantity = $meta['quantity'];
                }
                if ( $dimensions_summary === '' && isset( $meta['dimensions'] ) && is_array( $meta['dimensions'] ) ) {
                    $d = $meta['dimensions'];
                    $w = isset( $d['width'] ) ? $d['width'] : ( isset( $d['w'] ) ? $d['w'] : '' );
                    $d2 = isset( $d['depth'] ) ? $d['depth'] : ( isset( $d['d'] ) ? $d['d'] : '' );
                    $h = isset( $d['height'] ) ? $d['height'] : ( isset( $d['h'] ) ? $d['h'] : '' );
                    $u = isset( $d['unit'] ) ? $d['unit'] : '';
                    $dimensions_summary = trim( ( $w !== '' ? $w : '' ) . ' Ã— ' . ( $d2 !== '' ? $d2 : '' ) . ' Ã— ' . ( $h !== '' ? $h : '' ) . ( $u !== '' ? ' ' . $u : '' ), ' Ã—' );
                }
            }
        }
        if ( $dimensions_summary === '' ) {
            $dimensions_summary = '';
        }
        if ( $item_quantity === '' ) {
            $item_quantity = '';
        }

        // Invited suppliers + bid status (Not submitted when no bid)
        $invited_suppliers = array();
        $rfq_routes_table = $wpdb->prefix . 'n88_rfq_routes';
        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$rfq_routes_table}'" ) === $rfq_routes_table ) {
            $routes = $wpdb->get_results( $wpdb->prepare(
                "SELECT route_id, supplier_id, route_type, status as route_status FROM {$rfq_routes_table} WHERE item_id = %d ORDER BY route_id",
                $item_id
            ), ARRAY_A );
            foreach ( $routes as $r ) {
                $bid_status = 'Not submitted';
                $bid_row = $wpdb->get_row( $wpdb->prepare(
                    "SELECT bid_id, status FROM {$item_bids_table} WHERE item_id = %d AND supplier_id = %d ORDER BY bid_id DESC LIMIT 1",
                    $item_id,
                    $r['supplier_id']
                ), ARRAY_A );
                if ( $bid_row && ! empty( $bid_row['status'] ) ) {
                    $bid_status = $bid_row['status'];
                } else {
                    $bid_status = ! empty( $r['route_status'] ) ? $r['route_status'] : 'Not submitted';
                }
                $invited_suppliers[] = array(
                    'supplier_id'  => $r['supplier_id'],
                    'route_type'   => $r['route_type'],
                    'route_status' => $r['route_status'],
                    'bid_status'   => $bid_status,
                );
            }
        }

        $designer_id = ! empty( $item['owner_user_id'] ) ? (int) $item['owner_user_id'] : 0;
        if ( ! $designer_id ) {
            $row = $wpdb->get_row( $wpdb->prepare(
                "SELECT designer_id FROM {$messages_table} WHERE item_id = %d AND thread_type = 'designer_operator' LIMIT 1",
                $item_id
            ), ARRAY_A );
            if ( $row && ! empty( $row['designer_id'] ) ) {
                $designer_id = (int) $row['designer_id'];
            }
        }

        // Supplier: get from any supplier_operator message for this item (bid_id can be 0/NULL when supplier asked before bidding)
        $supplier_id = 0;
        $row = $wpdb->get_row( $wpdb->prepare(
            "SELECT supplier_id FROM {$messages_table} WHERE item_id = %d AND thread_type = 'supplier_operator' AND (bid_id = %d OR (bid_id IS NULL AND %d = 0)) LIMIT 1",
            $item_id,
            $bid_id,
            $bid_id
        ), ARRAY_A );
        if ( $row && ! empty( $row['supplier_id'] ) ) {
            $supplier_id = (int) $row['supplier_id'];
        }
        if ( ! $supplier_id ) {
            $row = $wpdb->get_row( $wpdb->prepare(
                "SELECT supplier_id FROM {$messages_table} WHERE item_id = %d AND thread_type = 'supplier_operator' ORDER BY created_at DESC LIMIT 1",
                $item_id
            ), ARRAY_A );
            if ( $row && ! empty( $row['supplier_id'] ) ) {
                $supplier_id = (int) $row['supplier_id'];
            }
        }

        $designer_messages = array();
        if ( $designer_id ) {
            $designer_messages = $wpdb->get_results( $wpdb->prepare(
                "SELECT m.*, u.display_name as sender_name
                 FROM {$messages_table} m
                 LEFT JOIN {$users_table} u ON m.sender_user_id = u.ID
                 WHERE m.item_id = %d AND m.thread_type = 'designer_operator' AND m.designer_id = %d
                 ORDER BY m.created_at ASC",
                $item_id,
                $designer_id
            ), ARRAY_A );
        }

        $supplier_messages = array();
        if ( $supplier_id ) {
            $supplier_messages = $wpdb->get_results( $wpdb->prepare(
                "SELECT m.*, u.display_name as sender_name
                 FROM {$messages_table} m
                 LEFT JOIN {$users_table} u ON m.sender_user_id = u.ID
                 WHERE m.item_id = %d AND m.thread_type = 'supplier_operator' AND m.supplier_id = %d
                 AND (m.bid_id = %d OR (m.bid_id IS NULL AND %d = 0))
                 ORDER BY m.created_at ASC",
                $item_id,
                $supplier_id,
