    /**
     * AJAX: Get Operator Case Details (Read-Only) - Commit 2.3.9.1C
     */
    public function ajax_get_operator_case_details() {
        check_ajax_referer( 'n88_get_operator_case_details', '_ajax_nonce' );

        if ( ! is_user_logged_in() ) {
            wp_send_json_error( array( 'message' => 'Authentication required.' ) );
            return;
        }

        $current_user = wp_get_current_user();
        $is_system_operator = in_array( 'n88_system_operator', $current_user->roles, true );
        
        if ( ! $is_system_operator ) {
            wp_send_json_error( array( 'message' => 'Access denied. System Operator account required.' ) );
            return;
        }

        $payment_id = isset( $_POST['payment_id'] ) ? absint( $_POST['payment_id'] ) : 0;
        $clarification_item_id = isset( $_POST['item_id'] ) ? absint( $_POST['item_id'] ) : 0;
        $clarification_bid_id = isset( $_POST['bid_id'] ) ? absint( $_POST['bid_id'] ) : 0;

        // Clarification-only: no payment yet (e.g. supplier sent question before bid); load by item_id + bid_id
        if ( ! $payment_id && $clarification_item_id ) {
            $this->ajax_get_operator_case_details_clarification_only( $clarification_item_id, $clarification_bid_id );
            return;
        }

        if ( ! $payment_id ) {
            wp_send_json_error( array( 'message' => 'Invalid payment ID.' ) );
            return;
        }

        global $wpdb;
        $prototype_payments_table = $wpdb->prefix . 'n88_prototype_payments';
        $items_table = $wpdb->prefix . 'n88_items';
        $item_bids_table = $wpdb->prefix . 'n88_item_bids';
        $categories_table = $wpdb->prefix . 'n88_categories';
        $users_table = $wpdb->prefix . 'users';
        $events_table = $wpdb->prefix . 'n88_events';
        $keywords_table = $wpdb->prefix . 'n88_keywords';

        // Get prototype payment details
        $payment = $wpdb->get_row( $wpdb->prepare(
            "SELECT pp.*, i.title as item_title, i.item_type, b.unit_price,
             designer.display_name as designer_name, supplier.display_name as supplier_name
             FROM {$prototype_payments_table} pp
             LEFT JOIN {$items_table} i ON pp.item_id = i.id
             LEFT JOIN {$item_bids_table} b ON pp.bid_id = b.bid_id
             LEFT JOIN {$users_table} designer ON pp.designer_user_id = designer.ID
             LEFT JOIN {$users_table} supplier ON pp.supplier_id = supplier.ID
             WHERE pp.id = %d",
            $payment_id
        ), ARRAY_A );

        if ( ! $payment ) {
            wp_send_json_error( array( 'message' => 'Payment record not found.' ) );
            return;
        }

        // Get item thumbnail
        $thumbnail_url = '';
        if ( ! empty( $payment['item_id'] ) ) {
            $item = $wpdb->get_row( $wpdb->prepare(
                "SELECT primary_image_id FROM {$items_table} WHERE id = %d",
                $payment['item_id']
            ), ARRAY_A );
            if ( $item && ! empty( $item['primary_image_id'] ) ) {
                $thumbnail_url = wp_get_attachment_image_url( $item['primary_image_id'], 'thumbnail' );
                if ( ! $thumbnail_url ) {
                    $thumbnail_url = wp_get_attachment_url( $item['primary_image_id'] );
                }
            }
        }

        // Parse video direction JSON
        $video_direction = array();
        $selected_keywords = array();
        $note = '';
        $keyword_count = 0;
        if ( ! empty( $payment['video_direction_json'] ) ) {
            $video_direction = json_decode( $payment['video_direction_json'], true );
            if ( is_array( $video_direction ) ) {
                if ( isset( $video_direction['selected_keywords'] ) && is_array( $video_direction['selected_keywords'] ) ) {
                    $selected_keywords = $video_direction['selected_keywords'];
                    $keyword_count = count( $selected_keywords );
                }
                if ( isset( $video_direction['note'] ) ) {
                    $note = sanitize_textarea_field( $video_direction['note'] );
                }
            }
        }

        // Get keyword names
        $keyword_names = array();
        if ( ! empty( $selected_keywords ) ) {
            $keyword_ids = array_map( 'absint', $selected_keywords );
            $keyword_ids = array_filter( $keyword_ids );
            if ( ! empty( $keyword_ids ) ) {
                $placeholders = implode( ',', array_fill( 0, count( $keyword_ids ), '%d' ) );
                $keywords = $wpdb->get_results( $wpdb->prepare(
                    "SELECT keyword_id, keyword FROM {$keywords_table} WHERE keyword_id IN ({$placeholders}) ORDER BY keyword",
                    ...$keyword_ids
                ), ARRAY_A );
                foreach ( $keywords as $kw ) {
                    $keyword_names[] = $kw['keyword'];
                }
            }
        }

        // Get category name
        $category_name = ! empty( $payment['item_type'] ) ? $payment['item_type'] : 'Uncategorized';
        if ( ! empty( $payment['item_type'] ) ) {
            $category = $wpdb->get_row( $wpdb->prepare(
                "SELECT name FROM {$categories_table} WHERE category_id = %d OR name = %s LIMIT 1",
                intval( $payment['item_type'] ),
                $payment['item_type']
            ) );
            if ( $category ) {
                $category_name = $category->name;
            }
        }

        // Get linked events
        $events = $wpdb->get_results( $wpdb->prepare(
            "SELECT event_type, created_at, payload_json 
             FROM {$events_table}
             WHERE object_type = 'prototype_payment' 
             AND object_id = %d
             AND event_type IN ('cad_prototype_requested', 'video_direction_submitted')
             ORDER BY created_at ASC",
            $payment_id
        ), ARRAY_A );

        // Operator display: landed prototype and total due (matches designer; fixes legacy wrong total_due_usd)
        $prototype_estimate_for_display = null;
        $total_due_for_display = floatval( $payment['cad_fee_usd'] );
        if ( $payment['prototype_video_cost_estimate_usd'] !== null && $payment['prototype_video_cost_estimate_usd'] !== '' && floatval( $payment['prototype_video_cost_estimate_usd'] ) > 0 ) {
            $supplier_profiles_table = $wpdb->prefix . 'n88_supplier_profiles';
            $origin_region = null;
            $duty_rate_override = null;
            if ( ! empty( $payment['supplier_id'] ) ) {
                $table_exists = $wpdb->get_var( "SHOW TABLES LIKE '{$supplier_profiles_table}'" ) === $supplier_profiles_table;
                if ( $table_exists ) {
                    $sp = $wpdb->get_row( $wpdb->prepare( "SELECT origin_region, duty_rate_override FROM {$supplier_profiles_table} WHERE supplier_id = %d", intval( $payment['supplier_id'] ) ), ARRAY_A );
                    if ( $sp ) {
                        $origin_region = isset( $sp['origin_region'] ) ? $sp['origin_region'] : null;
                        $duty_rate_override = isset( $sp['duty_rate_override'] ) ? $sp['duty_rate_override'] : null;
                    }
                }
            }
            $duty_rate = N88_RFQ_Helpers::n88_calculate_duty_rate( $origin_region, $duty_rate_override );
            $pl = N88_RFQ_Helpers::n88_calculate_landed_cost( floatval( $payment['prototype_video_cost_estimate_usd'] ), $duty_rate );
            $prototype_landed_val = ( $pl && isset( $pl['display_price'] ) ) ? floatval( $pl['display_price'] ) : floatval( $payment['prototype_video_cost_estimate_usd'] );
            $prototype_estimate_for_display = $prototype_landed_val;
            $total_due_for_display += $prototype_landed_val;
        }

        // Commit 2.3.9.1C-a: Get messages for both threads
        $messages_table = $wpdb->prefix . 'n88_item_messages';
        $users_table = $wpdb->prefix . 'users';
        
        // Get supplier thread messages
        $supplier_messages = array();
        if ( ! empty( $payment['bid_id'] ) && ! empty( $payment['supplier_id'] ) ) {
            $supplier_messages = $wpdb->get_results( $wpdb->prepare(
                "SELECT m.*, u.display_name as sender_name
                 FROM {$messages_table} m
                 LEFT JOIN {$users_table} u ON m.sender_user_id = u.ID
                 WHERE m.item_id = %d 
                 AND m.thread_type = 'supplier_operator'
                 AND m.bid_id = %d
                 AND m.supplier_id = %d
                 ORDER BY m.created_at ASC",
                $payment['item_id'],
                $payment['bid_id'],
                $payment['supplier_id']
            ), ARRAY_A );
        }
        
        // Get designer thread messages
        $designer_messages = array();
        if ( ! empty( $payment['designer_user_id'] ) ) {
            $designer_messages = $wpdb->get_results( $wpdb->prepare(
                "SELECT m.*, u.display_name as sender_name
                 FROM {$messages_table} m
                 LEFT JOIN {$users_table} u ON m.sender_user_id = u.ID
                 WHERE m.item_id = %d 
                 AND m.thread_type = 'designer_operator'
                 AND m.designer_id = %d
                 ORDER BY m.created_at ASC",
                $payment['item_id'],
                $payment['designer_user_id']
            ), ARRAY_A );
        }

        // Format dates
        $created_date = ! empty( $payment['created_at'] ) ? date( 'M d, Y g:i A', strtotime( $payment['created_at'] ) ) : '';

        // Item Case tab: delivery context, item basics, invited suppliers (operator-only)
        $item_id_for_case = (int) $payment['item_id'];
        $delivery_country = '';
        $delivery_postal = '';
        $item_quantity = '';
        $dimensions_summary = '';
        $delivery_quoting_note = '';
        $item_delivery_context_table = $wpdb->prefix . 'n88_item_delivery_context';
        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$item_delivery_context_table}'" ) === $item_delivery_context_table ) {
            $delivery_cols = $wpdb->get_col( "DESCRIBE {$item_delivery_context_table}" );
            $sel = array( 'delivery_country_code', 'delivery_postal_code' );
            if ( in_array( 'quantity', $delivery_cols, true ) ) {
                $sel[] = 'quantity';
            }
            if ( in_array( 'dimensions_json', $delivery_cols, true ) ) {
                $sel[] = 'dimensions_json';
            }
            if ( in_array( 'delivery_cost_usd', $delivery_cols, true ) ) {
                $sel[] = 'delivery_cost_usd';
            }
            if ( in_array( 'shipping_estimate_mode', $delivery_cols, true ) ) {
                $sel[] = 'shipping_estimate_mode';
            }
            $delivery_row = $wpdb->get_row( $wpdb->prepare(
                "SELECT " . implode( ', ', $sel ) . " FROM {$item_delivery_context_table} WHERE item_id = %d",
                $item_id_for_case
            ), ARRAY_A );
            if ( $delivery_row ) {
                $delivery_country = isset( $delivery_row['delivery_country_code'] ) ? $delivery_row['delivery_country_code'] : '';
                $delivery_postal = isset( $delivery_row['delivery_postal_code'] ) ? $delivery_row['delivery_postal_code'] : '';
                if ( isset( $delivery_row['quantity'] ) && $delivery_row['quantity'] !== null && $delivery_row['quantity'] !== '' ) {
                    $item_quantity = $delivery_row['quantity'];
                }
                if ( ! empty( $delivery_row['dimensions_json'] ) ) {
                    $dims = json_decode( $delivery_row['dimensions_json'], true );
                    if ( is_array( $dims ) ) {
                        $w = isset( $dims['width'] ) ? $dims['width'] : ( isset( $dims['w'] ) ? $dims['w'] : '' );
                        $d = isset( $dims['depth'] ) ? $dims['depth'] : ( isset( $dims['d'] ) ? $dims['d'] : '' );
                        $h = isset( $dims['height'] ) ? $dims['height'] : ( isset( $dims['h'] ) ? $dims['h'] : '' );
                        $u = isset( $dims['unit'] ) ? $dims['unit'] : '';
                        $dimensions_summary = trim( ( $w !== '' ? $w : '' ) . ' Ã— ' . ( $d !== '' ? $d : '' ) . ' Ã— ' . ( $h !== '' ? $h : '' ) . ( $u !== '' ? ' ' . $u : '' ), ' Ã—' );
                        if ( $dimensions_summary === ' Ã—  Ã— ' ) {
                            $dimensions_summary = '';
                        }
                    }
                }
                if ( isset( $delivery_row['delivery_cost_usd'] ) && $delivery_row['delivery_cost_usd'] !== null && $delivery_row['delivery_cost_usd'] !== '' && floatval( $delivery_row['delivery_cost_usd'] ) > 0 ) {
                    $delivery_quoting_note = 'Delivery (quoted): $' . number_format( floatval( $delivery_row['delivery_cost_usd'] ), 2 );
                } elseif ( isset( $delivery_row['shipping_estimate_mode'] ) && $delivery_row['shipping_estimate_mode'] === 'auto' ) {
                    $delivery_quoting_note = 'Shipping: instant estimate';
                } else {
                    $delivery_quoting_note = 'Shipping: manual quote';
                }
            }
        }
        if ( $item_quantity === '' && ! empty( $payment['item_id'] ) ) {
            $item_row = $wpdb->get_row( $wpdb->prepare(
                "SELECT meta_json FROM {$items_table} WHERE id = %d",
                $item_id_for_case
            ), ARRAY_A );
            if ( $item_row && ! empty( $item_row['meta_json'] ) ) {
                $meta = json_decode( $item_row['meta_json'], true );
                if ( is_array( $meta ) && isset( $meta['quantity'] ) ) {
                    $item_quantity = $meta['quantity'];
                }
                if ( $dimensions_summary === '' && isset( $meta['dimensions'] ) && is_array( $meta['dimensions'] ) ) {
                    $d = $meta['dimensions'];
                    $w = isset( $d['width'] ) ? $d['width'] : ( isset( $d['w'] ) ? $d['w'] : '' );
                    $d2 = isset( $d['depth'] ) ? $d['depth'] : ( isset( $d['d'] ) ? $d['d'] : '' );
                    $h = isset( $d['height'] ) ? $d['height'] : ( isset( $d['h'] ) ? $d['h'] : '' );
                    $u = isset( $d['unit'] ) ? $d['unit'] : '';
                    $dimensions_summary = trim( ( $w !== '' ? $w : '' ) . ' Ã— ' . ( $d2 !== '' ? $d2 : '' ) . ' Ã— ' . ( $h !== '' ? $h : '' ) . ( $u !== '' ? ' ' . $u : '' ), ' Ã—' );
                }
            }
        }
        if ( $dimensions_summary === '' ) {
            $dimensions_summary = '';
        }
        if ( $item_quantity === '' ) {
            $item_quantity = '';
        }

        // Invited suppliers and current bid statuses (operator-only)
        $invited_suppliers = array();
        $rfq_routes_table = $wpdb->prefix . 'n88_rfq_routes';
        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$rfq_routes_table}'" ) === $rfq_routes_table ) {
            $routes = $wpdb->get_results( $wpdb->prepare(
                "SELECT route_id, supplier_id, route_type, status as route_status FROM {$rfq_routes_table} WHERE item_id = %d ORDER BY route_id",
                $item_id_for_case
            ), ARRAY_A );
            foreach ( $routes as $r ) {
                $bid_status = '';
                $bid_row = $wpdb->get_row( $wpdb->prepare(
                    "SELECT bid_id, status FROM {$item_bids_table} WHERE item_id = %d AND supplier_id = %d ORDER BY bid_id DESC LIMIT 1",
                    $item_id_for_case,
                    $r['supplier_id']
                ), ARRAY_A );
                if ( $bid_row ) {
                    $bid_status = $bid_row['status'];
                } else {
                    $bid_status = $r['route_status'];
                }
                $invited_suppliers[] = array(
                    'supplier_id' => $r['supplier_id'],
                    'route_type'  => $r['route_type'],
                    'route_status' => $r['route_status'],
                    'bid_status'  => $bid_status,
                );
            }
        }

        // Tab 3 WorkFlow: key dates and gate state (from payment + events)
        $cad_requested_date = '';
        $video_direction_date = '';
        foreach ( $events as $ev ) {
            if ( $ev['event_type'] === 'cad_prototype_requested' ) {
                $cad_requested_date = ! empty( $ev['created_at'] ) ? date( 'M d, Y g:i A', strtotime( $ev['created_at'] ) ) : '';
                break;
            }
        }
        foreach ( $events as $ev ) {
            if ( $ev['event_type'] === 'video_direction_submitted' ) {
                $video_direction_date = ! empty( $ev['created_at'] ) ? date( 'M d, Y g:i A', strtotime( $ev['created_at'] ) ) : '';
                break;
            }
        }
        if ( $cad_requested_date === '' && ! empty( $payment['created_at'] ) ) {
            $cad_requested_date = date( 'M d, Y g:i A', strtotime( $payment['created_at'] ) );
        }
        $payment_requested_date = ! empty( $payment['created_at'] ) ? date( 'M d, Y g:i A', strtotime( $payment['created_at'] ) ) : '';
        $designer_payment_sent_date = '';
        $pp_cols = $wpdb->get_col( "DESCRIBE {$prototype_payments_table}" );
        if ( is_array( $pp_cols ) && in_array( 'payment_evidence_logged_at', $pp_cols, true ) && ! empty( $payment['payment_evidence_logged_at'] ) ) {
            $designer_payment_sent_date = date( 'M d, Y g:i A', strtotime( $payment['payment_evidence_logged_at'] ) );
        }
        $operator_payment_marked_date = ! empty( $payment['received_at'] ) ? date( 'M d, Y g:i A', strtotime( $payment['received_at'] ) ) : '';
        $cad_uploaded_date = '';
        $cad_uploaded_row = $wpdb->get_row( $wpdb->prepare(
            "SELECT MIN(created_at) as first_at FROM {$events_table} WHERE object_type = 'prototype_payment' AND object_id = %d AND event_type = 'cad_uploaded'",
            $payment_id
        ), ARRAY_A );
        if ( ! empty( $cad_uploaded_row['first_at'] ) ) {
            $cad_uploaded_date = date( 'M d, Y g:i A', strtotime( $cad_uploaded_row['first_at'] ) );
        }
        $cad_approved_date = ! empty( $payment['cad_approved_at'] ) ? date( 'M d, Y g:i A', strtotime( $payment['cad_approved_at'] ) ) : '';
        $cad_released_date = ! empty( $payment['cad_released_to_supplier_at'] ) && trim( $payment['cad_released_to_supplier_at'] ) !== '' ? date( 'M d, Y g:i A', strtotime( $payment['cad_released_to_supplier_at'] ) ) : '';
        $prototype_submitted_date = '';
        $pvs_table = $wpdb->prefix . 'n88_prototype_video_submissions';
        if ( $wpdb->get_var( "SHOW TABLES LIKE '{$pvs_table}'" ) === $pvs_table ) {
            $first_sub = $wpdb->get_var( $wpdb->prepare(
                "SELECT MIN(created_at) FROM {$pvs_table} WHERE payment_id = %d",
                $payment_id
            ) );
            if ( $first_sub ) {
                $prototype_submitted_date = date( 'M d, Y g:i A', strtotime( $first_sub ) );
            }
        }
        $prototype_approved_date = ! empty( $payment['prototype_approved_at'] ) ? date( 'M d, Y g:i A', strtotime( $payment['prototype_approved_at'] ) ) : '';
        $gate_state = 'Awaiting Payment';
        $pay_status = isset( $payment['status'] ) ? $payment['status'] : '';
        $cad_status_val = isset( $payment['cad_status'] ) ? $payment['cad_status'] : '';
        $cad_released = ! empty( $payment['cad_released_to_supplier_at'] ) && trim( $payment['cad_released_to_supplier_at'] ) !== '';
        $prototype_status_val = isset( $payment['prototype_status'] ) ? $payment['prototype_status'] : '';
        if ( $pay_status === 'marked_received' && ! $cad_released && $cad_status_val !== 'approved' ) {
            $gate_state = 'CAD In Progress';
        } elseif ( $pay_status === 'marked_received' && $cad_status_val === 'approved' && ! $cad_released ) {
            $gate_state = 'CAD Approved  Awaiting Release';
        } elseif ( $cad_released && ! in_array( $prototype_status_val, array( 'submitted', 'approved', 'changes_requested' ), true ) ) {
            $gate_state = 'Awaiting Prototype';
        } elseif ( $prototype_status_val === 'submitted' ) {
            $gate_state = 'Review Required';
        } elseif ( $prototype_status_val === 'changes_requested' ) {
            $gate_state = 'Changes Requested';
        } elseif ( $prototype_status_val === 'approved' ) {
            $gate_state = 'Prototype Approved';
        }
        // Commit 3.B.5B: Project Awarded block for Step 3 (operator)
        $operator_step3_project_awarded = ( $prototype_status_val === 'approved' );
        $operator_step3_supplier_name = ! empty( $payment['supplier_name'] ) ? $payment['supplier_name'] : 'Supplier #' . ( isset( $payment['supplier_id'] ) ? $payment['supplier_id'] : '' );
        $operator_step3_designer_name = ! empty( $payment['designer_name'] ) ? $payment['designer_name'] : 'Designer';
        $operator_step3_prototype_approved_date = $prototype_approved_date;
        $operator_step3_award_date = $prototype_approved_date;
        $items_table_local = $wpdb->prefix . 'n88_items';
        $item_meta_json = $wpdb->get_var( $wpdb->prepare( "SELECT meta_json FROM {$items_table_local} WHERE id = %d", $payment['item_id'] ) );
        if ( $item_meta_json ) {
            $item_meta_arr = json_decode( $item_meta_json, true );
            if ( is_array( $item_meta_arr ) && ! empty( $item_meta_arr['award_timestamp'] ) ) {
                $operator_step3_award_date = date( 'M d, Y g:i A', strtotime( $item_meta_arr['award_timestamp'] ) );
            }
        }
        // Commit 3.B.5A: Latest feedback packet for Step 3 when changes_requested (operator sees structured revision)
        $operator_latest_feedback = null;
        if ( $prototype_status_val === 'changes_requested' ) {
            $fb_table = $wpdb->prefix . 'n88_prototype_feedback_packets';
            $fpl_table = $wpdb->prefix . 'n88_prototype_feedback_packet_lines';
            $kp_table = $wpdb->prefix . 'n88_keyword_phrases';
            if ( $wpdb->get_var( "SHOW TABLES LIKE '{$fb_table}'" ) === $fb_table ) {
                $fp = $wpdb->get_row( $wpdb->prepare(
                    "SELECT id, submission_version, created_at FROM {$fb_table} WHERE payment_id = %d ORDER BY created_at DESC LIMIT 1",
                    $payment_id
                ), ARRAY_A );
                if ( $fp ) {
                    $fpl_has_rev = in_array( 'revision_detail', $wpdb->get_col( "DESCRIBE {$fpl_table}" ), true );
                    $sel = "SELECT fpl.keyword_id, fpl.keyword_status, fpl.severity, fpl.selected_phrase_ids" . ( $fpl_has_rev ? ", fpl.revision_detail" : "" ) . ", k.keyword as keyword_name FROM {$fpl_table} fpl LEFT JOIN {$keywords_table} k ON fpl.keyword_id = k.keyword_id WHERE fpl.feedback_packet_id = %d ORDER BY fpl.id ASC";
                    $lines = $wpdb->get_results( $wpdb->prepare( $sel, $fp['id'] ), ARRAY_A );
                    $kw_data = array();
                    foreach ( $lines as $line ) {
                        $phrase_ids = json_decode( isset( $line['selected_phrase_ids'] ) ? $line['selected_phrase_ids'] : '[]', true );
                        $phrases = array();
                        if ( ! empty( $phrase_ids ) && is_array( $phrase_ids ) ) {
                            $pids = array_map( 'absint', $phrase_ids );
                            $pids_str = implode( ',', $pids );
                            $phrase_rows = $wpdb->get_results( "SELECT phrase_id, phrase_text FROM {$kp_table} WHERE phrase_id IN ({$pids_str}) AND is_active = 1 ORDER BY FIELD(phrase_id, {$pids_str})", ARRAY_A );
                            foreach ( $phrase_rows as $pr ) {
                                $phrases[] = array( 'phrase_id' => (int) $pr['phrase_id'], 'phrase_text' => $pr['phrase_text'] );
                            }
                        }
                        $entry = array(
                            'keyword_id' => (int) $line['keyword_id'],
                            'keyword_name' => ! empty( $line['keyword_name'] ) ? $line['keyword_name'] : 'Keyword ' . $line['keyword_id'],
                            'keyword_status' => $line['keyword_status'],
                            'severity' => $line['severity'],
                            'phrases' => $phrases,
                        );
                        if ( $fpl_has_rev && isset( $line['revision_detail'] ) && trim( (string) $line['revision_detail'] ) !== '' ) {
                            $entry['revision_detail'] = $line['revision_detail'];
                        }
                        $kw_data[] = $entry;
                    }
                    $operator_latest_feedback = array(
                        'submission_version' => (int) $fp['submission_version'],
                        'created_at' => $fp['created_at'],
                        'keywords' => $kw_data,
                    );
                }
            }
        }
        // Current workflow step for operator: 0=Step 1 (Keywords), 1=Step 2 (Key Dates), 2=Step 3 (State); 4-6 stay at 2 until implemented
        $operator_current_step = 0;
        if ( $pay_status === 'marked_received' ) {
            $operator_current_step = 1;
        }
        if ( $cad_released || $cad_status_val === 'approved' || in_array( $prototype_status_val, array( 'submitted', 'approved', 'changes_requested' ), true ) ) {
            $operator_current_step = 2;
        }

