            return;
        }

        $current_version = $wpdb->get_var( $wpdb->prepare(
            "SELECT MAX(cad_version) FROM {$item_files_table}
             WHERE item_id = %d AND payment_id = %d AND attachment_type = 'cad' AND detached_at IS NULL",
